          chartJS.LinearScale,
          chartJS.PointElement,
          chartJS.LineElement,
          chartJS.BarElement,
          chartJS.ArcElement,
          chartJS.Title,
          chartJS.Tooltip,
          chartJS.Legend,
          chartJS.Filler
