  const fetchBillingData = async () => {
    try {
      const response = await billsAPI.getAll()
      const bills = response.data
      
      const today = new Date().toISOString().split('T')[0]
      const currentMonth = new Date().getMonth()
      const currentYear = new Date().getFullYear()
      
      // Filter today's bills
      const todayBills = bills.filter(bill => bill.billDate === today)
      
      // Filter this month's bills
      const thisMonthBills = bills.filter(bill => {
        const billDate = new Date(bill.billDate)
        return billDate.getMonth() === currentMonth && billDate.getFullYear() === currentYear
      })
      
      // Calculate income metrics
      const todayIncome = todayBills.reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
      const thisMonthIncome = thisMonthBills.reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
      
      const cashToday = todayBills
        .filter(bill => bill.paymentMethod === 'cash')
        .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
      const upiToday = todayBills
        .filter(bill => bill.paymentMethod === 'upi')
        .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
        
      const cashThisMonth = thisMonthBills
        .filter(bill => bill.paymentMethod === 'cash')
        .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
      const upiThisMonth = thisMonthBills
        .filter(bill => bill.paymentMethod === 'upi')
        .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
      
      setBillingData({
        todayIncome,
        thisMonthIncome,
        cashToday,
        upiToday,
        cashThisMonth,
        upiThisMonth
      })
    } catch (error) {
      console.log('Billing API unavailable, no fallback data')
      // Set empty values when API is not available
      setBillingData({
        todayIncome: 0,
        thisMonthIncome: 0,
        cashToday: 0,
        upiToday: 0,
        cashThisMonth: 0,
        upiThisMonth: 0
      })
    }
  }

  const fetchExpenseData = async () => {
    try {
      const response = await expensesAPI.getAll()
      const expenses = response.data
      
      const today = new Date().toISOString().split('T')[0]
      const currentMonth = new Date().getMonth()
      const currentYear = new Date().getFullYear()
      
      // Filter today's expenses
      const todayExpenses = expenses.filter(expense => expense.date === today)
      
      // Filter this month's expenses
      const thisMonthExpenses = expenses.filter(expense => {
        const expenseDate = new Date(expense.date)
        return expenseDate.getMonth() === currentMonth && expenseDate.getFullYear() === currentYear
      })
      
      // Calculate expense metrics
      const todayTotal = todayExpenses.reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
      const thisMonthTotal = thisMonthExpenses.reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
      
      const cashToday = todayExpenses
        .filter(expense => expense.paymentMethod === 'cash' || expense.paymentMode === 'cash')
        .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
      const upiToday = todayExpenses
        .filter(expense => expense.paymentMethod === 'upi' || expense.paymentMode === 'upi')
        .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
        
      const cashThisMonth = thisMonthExpenses
        .filter(expense => expense.paymentMethod === 'cash' || expense.paymentMode === 'cash')
        .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
      const upiThisMonth = thisMonthExpenses
        .filter(expense => expense.paymentMethod === 'upi' || expense.paymentMode === 'upi')
        .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
      
      setExpenseData({
        todayExpenses: todayTotal,
        thisMonthExpenses: thisMonthTotal,
        cashToday,
        upiToday,
        cashThisMonth,
        upiThisMonth
      })
    } catch (error) {
      console.log('Expenses API not available, trying localStorage...')
      
      // Try to get expenses from localStorage as fallback
      try {
        const savedExpenses = localStorage.getItem('expenses')
        if (savedExpenses) {
          const expenses = JSON.parse(savedExpenses)
          
          const today = new Date().toISOString().split('T')[0]
          const currentMonth = new Date().getMonth()
          const currentYear = new Date().getFullYear()
          
          // Filter today's expenses
          const todayExpenses = expenses.filter(expense => expense.date === today)
          
          // Filter this month's expenses
          const thisMonthExpenses = expenses.filter(expense => {
            const expenseDate = new Date(expense.date)
            return expenseDate.getMonth() === currentMonth && expenseDate.getFullYear() === currentYear
          })
          
          // Calculate expense metrics
          const todayTotal = todayExpenses.reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
          const thisMonthTotal = thisMonthExpenses.reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
          
          const cashToday = todayExpenses
            .filter(expense => expense.paymentMethod === 'cash' || expense.paymentMode === 'cash')
            .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
          const upiToday = todayExpenses
            .filter(expense => expense.paymentMethod === 'upi' || expense.paymentMode === 'upi')
            .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
            
          const cashThisMonth = thisMonthExpenses
            .filter(expense => expense.paymentMethod === 'cash' || expense.paymentMode === 'cash')
            .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
          const upiThisMonth = thisMonthExpenses
            .filter(expense => expense.paymentMethod === 'upi' || expense.paymentMode === 'upi')
            .reduce((sum, expense) => sum + (expense.amount || expense.total || 0), 0)
          
          setExpenseData({
            todayExpenses: todayTotal,
            thisMonthExpenses: thisMonthTotal,
            cashToday,
            upiToday,
            cashThisMonth,
            upiThisMonth
          })
          
          console.log('Using expense data from localStorage:', {
            todayExpenses: todayTotal,
            thisMonthExpenses: thisMonthTotal,
            cashToday,
            upiToday,
            cashThisMonth,
            upiThisMonth
          })
        } else {
          // No localStorage data either, use fallback
          console.log('No expense data found, using fallback values')
          setExpenseData({
            todayExpenses: 0,
            thisMonthExpenses: 0,
            cashToday: 0,
            upiToday: 0,
            cashThisMonth: 0,
            upiThisMonth: 0
          })
        }
      } catch (localStorageError) {
        console.log('localStorage access failed, using fallback values')
        // Set fallback values when both API and localStorage fail
        setExpenseData({
          todayExpenses: 0,
          thisMonthExpenses: 0,
          cashToday: 0,
          upiToday: 0,
          cashThisMonth: 0,
          upiThisMonth: 0
        })
      }
    }
  }

  const fetchBirthdayData = async () => {
    try {
      const today = new Date()
      const todayMonth = today.getMonth() + 1 // JavaScript months are 0-indexed
      const todayDay = today.getDate()
      
      // Fetch customers data
      const customersResponse = await customersAPI.getAll()
      const customers = customersResponse.data
      
      // Try to fetch reminders data, but handle errors gracefully
      let reminders = []
      try {
        const remindersResponse = await remindersAPI.getAll()
        reminders = remindersResponse.data
      } catch (reminderError) {
        console.log('Reminders API not available, using customer data only')
      }
      
      // Calculate customer birthdays today
      const customerBirthdays = customers.filter(customer => {
        if (!customer.dateOfBirth) return false
        const birthDate = new Date(customer.dateOfBirth)
        return birthDate.getMonth() + 1 === todayMonth && birthDate.getDate() === todayDay
      }).length
      
      // Calculate birthday reminders today (if reminders data is available)
      const birthdayReminders = reminders.filter(reminder => {
        if (!reminder.reminderDate) return false
        const reminderDate = new Date(reminder.reminderDate)
        return reminderDate.getMonth() + 1 === todayMonth && reminderDate.getDate() === todayDay && 
               reminder.notes && reminder.notes.toLowerCase().includes('birthday')
      }).length
      
      // Staff birthdays (you can modify this logic based on your staff data structure)
      const staffBirthdays = 0 // Placeholder - implement staff birthday logic if needed
      
      const totalBirthdays = customerBirthdays + staffBirthdays
      
      setBirthdayData({
        customers: customerBirthdays,
        staff: staffBirthdays,
        total: totalBirthdays
      })
    } catch (error) {
      console.log('Birthday data fetching incomplete, using fallback values')
      // Set fallback values on error
      setBirthdayData({
        customers: 0,
        staff: 0,
        total: 0
      })
    }
  }

  const fetchTasksData = async () => {
    try {
      const response = await maintenanceAPI.getAll()
      const maintenance = response.data
      
      const today = new Date().toISOString().split('T')[0]
      const currentWeekStart = new Date()
      currentWeekStart.setDate(currentWeekStart.getDate() - currentWeekStart.getDay())
      currentWeekStart.setHours(0, 0, 0, 0)
      
      // Categorize tasks based on maintenance data
      const pending = maintenance.filter(task => {
        const serviceDate = new Date(task.serviceDate)
        return serviceDate > new Date() && task.status !== 'completed'
      }).length
      
      const processing = maintenance.filter(task => {
        const serviceDate = new Date(task.serviceDate)
        return serviceDate <= new Date() && task.status !== 'completed'
      }).length
      
      const completed = maintenance.filter(task => task.status === 'completed').length
      
      // High priority tasks (overdue or urgent)
      const highPriority = maintenance.filter(task => {
        const serviceDate = new Date(task.serviceDate)
        const daysOverdue = Math.floor((new Date() - serviceDate) / (1000 * 60 * 60 * 24))
        return task.status !== 'completed' && daysOverdue > 0
      }).length
      
      // Due today
      const dueToday = maintenance.filter(task => {
        const serviceDate = new Date(task.serviceDate).toISOString().split('T')[0]
        return serviceDate === today && task.status !== 'completed'
      }).length
      
      // Completed today
      const completedToday = maintenance.filter(task => {
        if (task.status !== 'completed') return false
        const completedDate = task.updatedAt || task.serviceDate
        return new Date(completedDate).toISOString().split('T')[0] === today
      }).length
      
      // Completed this week
      const completedThisWeek = maintenance.filter(task => {
        if (task.status !== 'completed') return false
        const completedDate = new Date(task.updatedAt || task.serviceDate)
        return completedDate >= currentWeekStart
      }).length
      
      setTasksData({
        pending,
        processing,
        completed,
        highPriority,
        dueToday,
        completedToday,
        completedThisWeek
      })
    } catch (error) {
      console.log('Tasks API unavailable, no fallback data')
      // Set empty values when API is not available
      setTasksData({
        pending: 0,
        processing: 0,
        completed: 0,
        highPriority: 0,
        dueToday: 0,
        completedToday: 0,
        completedThisWeek: 0
      })
    }
  }

  const fetchCustomersData = async () => {
    try {
      const response = await customersAPI.getAll()
      const customers = response.data
      
      // Calculate customer metrics
      const currentMonth = new Date().getMonth()
      const currentYear = new Date().getFullYear()
      
      const newThisMonth = customers.filter(customer => {
        const createdDate = new Date(customer.createdAt || customer.dateOfBirth)
        return createdDate.getMonth() === currentMonth && createdDate.getFullYear() === currentYear
      }).length
      
      // Consider all customers as active (you can modify this logic based on your business rules)
      const active = customers.length
      
      // Simple retention calculation (you may want to implement more complex logic)
      const retentionRate = customers.length > 0 ? Math.round((active / customers.length) * 100) : 0
      
      setCustomersData({
        total: customers.length,
        newThisMonth: newThisMonth,
        active: active,
        retentionRate: retentionRate
      })
    } catch (error) {
      console.log('Customers API unavailable, no fallback data')
      // Set empty values when API is not available
      setCustomersData({
        total: 0,
        newThisMonth: 0,
        active: 0,
        retentionRate: 0
      })
    }
  }

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getSummary({ timeout: 90000 })
      setData(response.data)
    } catch (error) {
      console.error('Dashboard error:', error)
      toast.error('Failed to fetch dashboard data')
      
      // Show user-friendly error message
      if (error.code === 'ECONNABORTED' || error.message?.includes('timeout')) {
        toast.error('Connection timeout. Please check your network and try again.')
      } else if (error.response?.status === 401) {
        toast.error('Authentication failed. Please check your credentials.')
      } else if (error.response?.status === 404) {
        toast.error('Dashboard data not found.')
      } else if (error.response?.status === 500) {
        toast.error('Server error. Using demo data for now.')
      } else {
        toast.error('Backend server not available. Using demo data.')
      }
    } finally {
      setLoading(false)
    }
  }

