import React from 'react'

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props)
    this.state = { hasError: false, error: null, errorInfo: null }
  }

  static getDerivedStateFromError(error) {
    // Update state so the next render will show the fallback UI
    return { hasError: true }
  }

  componentDidCatch(error, errorInfo) {
    // You can also log the error to an error reporting service here
    console.error('ErrorBoundary caught an error:', error, errorInfo)
    
    this.setState({
      error: error,
      errorInfo: errorInfo
    })
  }

  render() {
    if (this.state.hasError) {
      // You can render any custom fallback UI
      return (
        <div className="min-h-screen bg-gray-50 flex items-center justify-center">
          <div className="text-center p-8">
            <div className="bg-red-50 border-l-4 border-red-500 rounded-xl shadow-lg p-8 max-w-md">
              <div className="flex flex-col items-center space-y-4">
                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center">
                  <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h.019M12 19v-6m0 7v6m0 7v6m0-13v-1h-7v-1h-7v-1h7v7h7v7h-7v-1h-7v-1h-7v-1h7v-1" />
                  </svg>
                </div>
                
                <h2 className="text-2xl font-bold text-red-800 mb-2">Something went wrong</h2>
                <p className="text-red-600 mb-4">An unexpected error occurred while loading the dashboard.</p>
                
                <div className="bg-red-100 rounded-lg p-4 text-left">
                  <p className="text-sm font-semibold text-red-800 mb-2">Error Details:</p>
                  {this.state.error && (
                    <p className="text-xs text-red-700 font-mono bg-red-50 p-2 rounded mt-2">
                      {this.state.error.toString()}
                    </p>
                  )}
                  
                  {this.state.errorInfo && (
                    <div className="mt-3">
                      <p className="text-xs font-semibold text-red-800 mb-1">Component Stack:</p>
                      <p className="text-xs text-red-600 font-mono bg-red-50 p-2 rounded">
                        {this.state.errorInfo.componentStack}
                      </p>
                    </div>
                  )}
                </div>
                
                <div className="flex space-x-4 mt-6">
                  <button
                    onClick={() => window.location.reload()}
                    className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition-colors"
                  >
                    Reload Page
                  </button>
                  <button
                    onClick={() => window.location.href = '/'}
                    className="bg-gray-600 text-white px-4 py-2 rounded-lg hover:bg-gray-700 transition-colors"
                  >
                    Go to Home
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )
    }

    return this.props.children
  }
}

export default ErrorBoundary
