import { useState } from 'react'
import { 
  ExternalLink, 
  Edit, 
  Trash2, 
  Heart, 
  MoreVertical,
  Globe,
  Clock,
  Tag,
  Star,
  Copy,
  Share2
} from 'lucide-react'

const BookmarkCard = ({ 
  bookmark, 
  viewMode, 
  onEdit, 
  onDelete, 
  onToggleFavorite, 
  onUrlClick 
}) => {
  const [showActions, setShowActions] = useState(false)
  const [isHovered, setIsHovered] = useState(false)

  const getFaviconUrl = (url) => {
    try {
      const domain = new URL(url).hostname
      return `https://www.google.com/s2/favicons?domain=${domain}&sz=64`
    } catch {
      return null
    }
  }

  const handleCardClick = (e) => {
    // Don't open URL if clicking on action buttons
    if (e.target.closest('.bookmark-actions')) return
    if (e.target.closest('button')) return
    onUrlClick(bookmark.url)
  }

  const cardClasses = viewMode === 'grid' 
    ? `group relative bg-gradient-to-br from-white to-gray-50 rounded-2xl shadow-lg hover:shadow-2xl transition-all duration-500 transform hover:scale-105 cursor-pointer border border-gray-100 overflow-hidden backdrop-blur-sm ${
        isHovered ? 'ring-4 ring-blue-400 ring-opacity-30 shadow-blue-200/50' : ''
      } ${bookmark.isFavorite ? 'ring-2 ring-yellow-400 ring-opacity-50' : ''}`
    : `group relative bg-gradient-to-r from-white to-gray-50 rounded-xl shadow-md hover:shadow-xl transition-all duration-300 border border-gray-100 cursor-pointer ${
        isHovered ? 'ring-2 ring-blue-400 ring-opacity-30 translate-x-1' : ''
      } ${bookmark.isFavorite ? 'ring-1 ring-yellow-400 ring-opacity-50' : ''}`

  return (
    <div
      className={cardClasses}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleCardClick}
    >
      {viewMode === 'grid' ? (
        // Grid View
        <div className="p-6 relative">
          {/* Gradient Overlay */}
          <div className="absolute inset-0 bg-gradient-to-br from-blue-400/5 to-purple-400/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300 rounded-2xl"></div>
          
          {/* Header */}
          <div className="flex items-start justify-between mb-4 relative z-10">
            <div className="flex items-center space-x-3">
              <div className="relative group/icon">
                {bookmark.favicon ? (
                  <img 
                    src={bookmark.favicon} 
                    alt={bookmark.serviceName}
                    className="w-12 h-12 rounded-xl object-cover ring-2 ring-white shadow-lg group-hover/icon:scale-110 transition-transform duration-300"
                    onError={(e) => {
                      e.target.style.display = 'none'
                      e.target.nextElementSibling.style.display = 'flex'
                    }}
                  />
                ) : null}
                <div 
                  className="w-12 h-12 rounded-xl flex items-center justify-center text-white font-bold text-lg shadow-lg ring-2 ring-white group-hover/icon:scale-110 transition-all duration-300"
                  style={{ 
                    background: `linear-gradient(135deg, ${bookmark.color || '#3b82f6'}, ${bookmark.color ? bookmark.color + 'cc' : '#2563eb'})`, 
                    display: bookmark.favicon ? 'none' : 'flex' 
                  }}
                >
                  {bookmark.serviceName.charAt(0).toUpperCase()}
                </div>
                {bookmark.isFavorite && (
                  <div className="absolute -top-2 -right-2 animate-pulse">
                    <div className="bg-gradient-to-r from-yellow-400 to-orange-400 rounded-full p-1 shadow-lg">
                      <Heart className="h-3 w-3 text-white fill-current" />
                    </div>
                  </div>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="font-bold text-gray-900 truncate text-lg group-hover:text-blue-600 transition-colors duration-300">
                  {bookmark.serviceName}
                </h3>
                <p className="text-xs text-gray-500 truncate flex items-center mt-1">
                  <Globe className="h-3 w-3 mr-1" />
                  {new URL(bookmark.url).hostname}
                </p>
              </div>
            </div>
            
            <div className="bookmark-actions relative">
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  setShowActions(!showActions)
                }}
                className="p-2 rounded-xl hover:bg-white/80 backdrop-blur-sm transition-all duration-200 shadow-sm hover:shadow-md"
              >
                <MoreVertical className="h-4 w-4 text-gray-500" />
              </button>
              
              {showActions && (
                <div className="absolute right-0 top-full mt-2 bg-white/95 backdrop-blur-md border border-gray-200 rounded-xl shadow-2xl z-20 py-2 min-w-[140px] animate-in fade-in slide-in-from-top-2 duration-200">
                  <button
                    onClick={(e) => {
                      e.stopPropagation()
                      onToggleFavorite(bookmark._id)
                      setShowActions(false)
                    }}
                    className="w-full px-3 py-2 text-left text-sm text-gray-700 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 flex items-center space-x-2 transition-colors"
                  >
                    <Star className={`h-4 w-4 ${bookmark.isFavorite ? 'fill-current text-yellow-500' : ''}`} />
                    <span>{bookmark.isFavorite ? 'Unfavorite' : 'Favorite'}</span>
                  </button>
                  <button
                    onClick={(e) => {
                      e.stopPropagation()
                      navigator.clipboard.writeText(bookmark.url)
                      setShowActions(false)
                    }}
                    className="w-full px-3 py-2 text-left text-sm text-gray-700 hover:bg-gradient-to-r hover:from-green-50 hover:to-emerald-50 flex items-center space-x-2 transition-colors"
                  >
                    <Copy className="h-4 w-4" />
                    <span>Copy Link</span>
                  </button>
                  <button
                    onClick={(e) => {
                      e.stopPropagation()
                      onEdit(bookmark)
                      setShowActions(false)
                    }}
                    className="w-full px-3 py-2 text-left text-sm text-gray-700 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 flex items-center space-x-2 transition-colors"
                  >
                    <Edit className="h-4 w-4" />
                    <span>Edit</span>
                  </button>
                  <button
                    onClick={(e) => {
                      e.stopPropagation()
                      onDelete(bookmark._id)
                      setShowActions(false)
                    }}
                    className="w-full px-3 py-2 text-left text-sm text-red-600 hover:bg-gradient-to-r hover:from-red-50 hover:to-pink-50 flex items-center space-x-2 transition-colors"
                  >
                    <Trash2 className="h-4 w-4" />
                    <span>Delete</span>
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Description */}
          {bookmark.description && (
            <p className="text-sm text-gray-600 mb-4 line-clamp-2 relative z-10 leading-relaxed">
              {bookmark.description}
            </p>
          )}

          {/* Tags */}
          {bookmark.tags && bookmark.tags.length > 0 && (
            <div className="flex flex-wrap gap-1.5 mb-4 relative z-10">
              {bookmark.tags.slice(0, 3).map((tag, index) => (
                <span
                  key={index}
                  className="inline-flex items-center px-2.5 py-1 text-xs bg-gradient-to-r from-blue-50 to-purple-50 text-blue-700 rounded-full border border-blue-200 hover:border-blue-300 transition-colors"
                >
                  <Tag className="h-2.5 w-2.5 mr-1" />
                  {tag}
                </span>
              ))}
              {bookmark.tags.length > 3 && (
                <span className="inline-flex items-center px-2.5 py-1 text-xs bg-gradient-to-r from-gray-50 to-gray-100 text-gray-600 rounded-full border border-gray-200">
                  +{bookmark.tags.length - 3}
                </span>
              )}
            </div>
          )}

          {/* Footer */}
          <div className="flex items-center justify-between relative z-10">
            {bookmark.category && (
              <span className="text-xs text-gray-500 bg-gradient-to-r from-gray-50 to-gray-100 px-3 py-1.5 rounded-lg border border-gray-200 font-medium">
                {bookmark.category}
              </span>
            )}
            <div className="flex items-center text-xs text-gray-400 group-hover:text-blue-500 transition-colors duration-300">
              <ExternalLink className="h-3 w-3 mr-1 group-hover:animate-pulse" />
              <span className="font-medium">Visit</span>
            </div>
          </div>
        </div>
      ) : (
        // List View
        <div className="p-4 relative">
          <div className="absolute inset-0 bg-gradient-to-r from-blue-400/3 to-purple-400/3 opacity-0 group-hover:opacity-100 transition-opacity duration-300 rounded-xl"></div>
          <div className="flex items-center justify-between relative z-10">
            <div className="flex items-center space-x-4 flex-1">
              <div className="relative group/icon">
                {bookmark.favicon ? (
                  <img 
                    src={bookmark.favicon} 
                    alt={bookmark.serviceName}
                    className="w-10 h-10 rounded-lg object-cover ring-2 ring-white shadow-md group-hover/icon:scale-110 transition-transform duration-300"
                    onError={(e) => {
                      e.target.style.display = 'none'
                      e.target.nextElementSibling.style.display = 'flex'
                    }}
                  />
                ) : null}
                <div 
                  className="w-10 h-10 rounded-lg flex items-center justify-center text-white font-bold text-sm shadow-md ring-2 ring-white group-hover/icon:scale-110 transition-all duration-300"
                  style={{ 
                    background: `linear-gradient(135deg, ${bookmark.color || '#3b82f6'}, ${bookmark.color ? bookmark.color + 'cc' : '#2563eb'})`, 
                    display: bookmark.favicon ? 'none' : 'flex' 
                  }}
                >
                  {bookmark.serviceName.charAt(0).toUpperCase()}
                </div>
                {bookmark.isFavorite && (
                  <div className="absolute -top-1.5 -right-1.5">
                    <div className="bg-gradient-to-r from-yellow-400 to-orange-400 rounded-full p-0.5 shadow-md">
                      <Heart className="h-2.5 w-2.5 text-white fill-current" />
                    </div>
                  </div>
                )}
              </div>
              
              <div className="flex-1 min-w-0">
                <div className="flex items-center space-x-2">
                  <h3 className="font-semibold text-gray-900 truncate group-hover:text-blue-600 transition-colors duration-300">
                    {bookmark.serviceName}
                  </h3>
                  {bookmark.category && (
                    <span className="text-xs text-gray-500 bg-gradient-to-r from-gray-50 to-gray-100 px-2 py-1 rounded-md border border-gray-200 font-medium">
                      {bookmark.category}
                    </span>
                  )}
                </div>
                <p className="text-sm text-gray-500 truncate flex items-center mt-1">
                  <Globe className="h-3 w-3 mr-1" />
                  {bookmark.url}
                </p>
                {bookmark.description && (
                  <p className="text-sm text-gray-600 truncate mt-1 leading-relaxed">
                    {bookmark.description}
                  </p>
                )}
                {bookmark.tags && bookmark.tags.length > 0 && (
                  <div className="flex items-center space-x-1 mt-2">
                    {bookmark.tags.slice(0, 2).map((tag, index) => (
                      <span
                        key={index}
                        className="inline-flex items-center px-2 py-0.5 text-xs bg-gradient-to-r from-blue-50 to-purple-50 text-blue-700 rounded-full border border-blue-200"
                      >
                        <Tag className="h-2 w-2 mr-1" />
                        {tag}
                      </span>
                    ))}
                    {bookmark.tags.length > 2 && (
                      <span className="text-xs text-gray-500">+{bookmark.tags.length - 2} more</span>
                    )}
                  </div>
                )}
              </div>
            </div>

            <div className="flex items-center space-x-1 bookmark-actions">
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  onToggleFavorite(bookmark._id)
                }}
                className="p-2 rounded-lg hover:bg-white/80 backdrop-blur-sm transition-all duration-200 shadow-sm hover:shadow-md"
              >
                <Star className={`h-4 w-4 ${bookmark.isFavorite ? 'fill-current text-yellow-500' : 'text-gray-400'}`} />
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  navigator.clipboard.writeText(bookmark.url)
                }}
                className="p-2 rounded-lg hover:bg-white/80 backdrop-blur-sm transition-all duration-200 shadow-sm hover:shadow-md"
              >
                <Copy className="h-4 w-4 text-gray-400" />
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  onEdit(bookmark)
                }}
                className="p-2 rounded-lg hover:bg-white/80 backdrop-blur-sm transition-all duration-200 shadow-sm hover:shadow-md"
              >
                <Edit className="h-4 w-4 text-gray-400" />
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  onDelete(bookmark._id)
                }}
                className="p-2 rounded-lg hover:bg-red-50 transition-all duration-200 shadow-sm hover:shadow-md hover:shadow-red-100"
              >
                <Trash2 className="h-4 w-4 text-gray-400 hover:text-red-500" />
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  onUrlClick(bookmark.url)
                }}
                className="p-2 rounded-lg hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 transition-all duration-200 shadow-sm hover:shadow-md"
              >
                <ExternalLink className="h-4 w-4 text-gray-400 group-hover:text-blue-500" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default BookmarkCard
