import React, { useState, useEffect } from 'react'
import { Calendar, TrendingUp, TrendingDown, DollarSign, Filter, Download, Search, RefreshCw, ArrowUpRight, ArrowDownRight, Users, Receipt, CreditCard, Banknote } from 'lucide-react'
import { billsAPI, expensesAPI } from '../services/api'
import { toast } from 'react-hot-toast'

const IncomeExpense = () => {
  const [activeTab, setActiveTab] = useState('income')
  const [bills, setBills] = useState([])
  const [expenses, setExpenses] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterDate, setFilterDate] = useState('')
  const [filterMonth, setFilterMonth] = useState('')
  const [filterYear, setFilterYear] = useState(new Date().getFullYear().toString())
  const [searchTerm, setSearchTerm] = useState('')
  const [filterPaymentMethod, setFilterPaymentMethod] = useState('all')
  const [filterCategory, setFilterCategory] = useState('all')

  // Summary calculations
  const [summary, setSummary] = useState({
    totalIncome: 0,
    totalExpense: 0,
    profit: 0,
    profitMargin: 0,
    totalTransactions: 0,
    averageTransaction: 0,
    todayIncome: 0,
    todayExpense: 0,
    todayProfit: 0,
    todayCashIncome: 0,
    todayUPIIncome: 0,
    todayCreditCardIncome: 0,
    todayBankTransferIncome: 0,
    thisMonthIncome: 0,
    thisMonthExpense: 0,
    thisMonthProfit: 0,
    thisYearIncome: 0,
    thisYearExpense: 0,
    thisYearProfit: 0
  })

  useEffect(() => {
    fetchFinancialData()
  }, [filterMonth, filterYear, filterDate, searchTerm, filterPaymentMethod, filterCategory, activeTab])

  const fetchFinancialData = async () => {
    try {
      setLoading(true)
      
      // Fetch bills data
      const billsResponse = await billsAPI.getAll()
      const allBills = billsResponse.data || []
      
      // Fetch expenses data
      const expensesResponse = await expensesAPI.getAll()
      const allExpenses = expensesResponse.data || []
      
      // Apply filters
      const filteredBills = filterData(allBills, 'income')
      const filteredExpenses = filterData(allExpenses, 'expense')
      
      setBills(filteredBills)
      setExpenses(filteredExpenses)
      
      // Calculate summary
      calculateSummary(filteredBills, filteredExpenses)
    } catch (error) {
      console.error('Error fetching financial data:', error)
      toast.error('Failed to load financial data')
    } finally {
      setLoading(false)
    }
  }

  const filterData = (data, type) => {
    return data.filter(item => {
      const itemDate = new Date(item.billDate || item.date || item.createdAt)
      
      // Year filter
      if (filterYear && itemDate.getFullYear().toString() !== filterYear) {
        return false
      }
      
      // Month filter
      if (filterMonth) {
        const itemMonth = (itemDate.getMonth() + 1).toString().padStart(2, '0')
        if (itemMonth !== filterMonth) {
          return false
        }
      }
      
      // Date filter
      if (filterDate) {
        const itemDateStr = itemDate.toISOString().split('T')[0]
        if (itemDateStr !== filterDate) {
          return false
        }
      }
      
      // Search filter
      if (searchTerm) {
        const searchLower = searchTerm.toLowerCase()
        const matchesSearch = 
          (item.customerName && item.customerName.toLowerCase().includes(searchLower)) ||
          (item.billNo && item.billNo.toLowerCase().includes(searchLower)) ||
          (item.description && item.description.toLowerCase().includes(searchLower)) ||
          (item.category && item.category.toLowerCase().includes(searchLower)) ||
          (item.name && item.name.toLowerCase().includes(searchLower))
        
        if (!matchesSearch) {
          return false
        }
      }
      
      // Payment method filter (for income)
      if (type === 'income' && filterPaymentMethod !== 'all') {
        if (item.paymentMethod !== filterPaymentMethod) {
          return false
        }
      }
      
      // Category filter (for expenses)
      if (type === 'expense' && filterCategory !== 'all') {
        if (item.category !== filterCategory) {
          return false
        }
      }
      
      return true
    })
  }

  const calculateSummary = (incomeData, expenseData) => {
    const totalIncome = incomeData.reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    const totalExpense = expenseData.reduce((sum, expense) => sum + (expense.amount || 0), 0)
    const profit = totalIncome - totalExpense
    const profitMargin = totalIncome > 0 ? (profit / totalIncome) * 100 : 0
    const totalTransactions = incomeData.length + expenseData.length
    const averageTransaction = totalTransactions > 0 ? (totalIncome + totalExpense) / totalTransactions : 0

    // Get today's date
    const today = new Date()
    const todayStr = today.toISOString().split('T')[0]
    const currentMonth = today.getMonth()
    const currentYear = today.getFullYear()

    // Calculate today's income and expense with payment method breakdown
    const todayIncomeData = incomeData.filter(bill => new Date(bill.billDate || bill.createdAt).toISOString().split('T')[0] === todayStr)
    const todayIncome = todayIncomeData.reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    // Calculate today's income by payment method
    const todayCashIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'cash')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayUPIIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'upi')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayCreditCardIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'credit_card')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayBankTransferIncome = todayIncomeData
      .filter(bill => bill.paymentMethod === 'bank_transfer')
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const todayExpense = expenseData
      .filter(expense => new Date(expense.date || expense.createdAt).toISOString().split('T')[0] === todayStr)
      .reduce((sum, expense) => sum + (expense.amount || 0), 0)
    
    const todayProfit = todayIncome - todayExpense

    // Calculate this month's income and expense
    const thisMonthIncome = incomeData
      .filter(bill => {
        const billDate = new Date(bill.billDate || bill.createdAt)
        return billDate.getMonth() === currentMonth && billDate.getFullYear() === currentYear
      })
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const thisMonthExpense = expenseData
      .filter(expense => {
        const expenseDate = new Date(expense.date || expense.createdAt)
        return expenseDate.getMonth() === currentMonth && expenseDate.getFullYear() === currentYear
      })
      .reduce((sum, expense) => sum + (expense.amount || 0), 0)
    
    const thisMonthProfit = thisMonthIncome - thisMonthExpense

    // Calculate this year's income and expense
    const thisYearIncome = incomeData
      .filter(bill => new Date(bill.billDate || bill.createdAt).getFullYear() === currentYear)
      .reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    
    const thisYearExpense = expenseData
      .filter(expense => new Date(expense.date || expense.createdAt).getFullYear() === currentYear)
      .reduce((sum, expense) => sum + (expense.amount || 0), 0)
    
    const thisYearProfit = thisYearIncome - thisYearExpense

    setSummary({
      totalIncome,
      totalExpense,
      profit,
      profitMargin,
      totalTransactions,
      averageTransaction,
      todayIncome,
      todayExpense,
      todayProfit,
      todayCashIncome,
      todayUPIIncome,
      todayCreditCardIncome,
      todayBankTransferIncome,
      thisMonthIncome,
      thisMonthExpense,
      thisMonthProfit,
      thisYearIncome,
      thisYearExpense,
      thisYearProfit
    })
  }

  const clearFilters = () => {
    setFilterDate('')
    setFilterMonth('')
    setFilterYear(new Date().getFullYear().toString())
    setSearchTerm('')
    setFilterPaymentMethod('all')
    setFilterCategory('all')
  }

  const exportData = () => {
    const data = activeTab === 'income' ? bills : expenses
    const csvContent = generateCSV(data, activeTab)
    downloadCSV(csvContent, `${activeTab}-report.csv`)
  }

  const generateCSV = (data, type) => {
    if (type === 'income') {
      const headers = ['Bill No', 'Date', 'Customer', 'Amount', 'Payment Method', 'Status']
      const rows = data.map(bill => [
        bill.billNo || '',
        new Date(bill.billDate || bill.createdAt).toLocaleDateString(),
        bill.customerName || '',
        bill.grandTotal || 0,
        bill.paymentMethod || '',
        bill.status || 'pending'
      ])
      return [headers, ...rows].map(row => row.join(',')).join('\n')
    } else {
      const headers = ['Date', 'Category', 'Description', 'Amount', 'Payment Method']
      const rows = data.map(expense => [
        new Date(expense.date || expense.createdAt).toLocaleDateString(),
        expense.category || '',
        expense.description || expense.name || '',
        expense.amount || 0,
        expense.paymentMethod || ''
      ])
      return [headers, ...rows].map(row => row.join(',')).join('\n')
    }
  }

  const downloadCSV = (content, filename) => {
    const blob = new Blob([content], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = filename
    a.click()
    window.URL.revokeObjectURL(url)
  }

  const getUniqueCategories = () => {
    const categories = [...new Set(expenses.map(exp => exp.category || exp.expenseCategory).filter(Boolean))]
    return categories.sort()
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Today's Summary Cards */}
      <div className="bg-gradient-to-r from-indigo-50 to-purple-50 rounded-xl p-6 border border-indigo-200">
        <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
          <Calendar className="h-5 w-5 text-indigo-600 mr-2" />
          Today's Summary
        </h3>
        
        {/* Main Summary */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mb-8">
          <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
            <div className="absolute inset-0 bg-gradient-to-br from-green-400/20 to-emerald-600/20"></div>
            <div className="relative p-8">
              <div className="flex items-center justify-between mb-6">
                <div className="bg-gradient-to-r from-green-500 to-emerald-500 rounded-3xl p-4 shadow-xl">
                  <TrendingUp className="h-8 w-8 text-white" />
                </div>
                <div className="bg-green-500/20 rounded-full px-4 py-2">
                  <span className="text-green-700 text-sm font-semibold">+12.5%</span>
                </div>
              </div>
              <div>
                <p className="text-gray-600 text-base font-medium mb-2">Today's Income</p>
                <p className="text-4xl font-bold text-gray-900">Rs. {summary.todayIncome.toFixed(2)}</p>
                <div className="mt-3 h-2 bg-gradient-to-r from-green-500 to-emerald-500 rounded-full"></div>
              </div>
            </div>
          </div>

          <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
            <div className="absolute inset-0 bg-gradient-to-br from-red-400/20 to-rose-600/20"></div>
            <div className="relative p-8">
              <div className="flex items-center justify-between mb-6">
                <div className="bg-gradient-to-r from-red-500 to-rose-500 rounded-3xl p-4 shadow-xl">
                  <TrendingDown className="h-8 w-8 text-white" />
                </div>
                <div className="bg-red-500/20 rounded-full px-4 py-2">
                  <span className="text-red-700 text-sm font-semibold">-8.3%</span>
                </div>
              </div>
              <div>
                <p className="text-gray-600 text-base font-medium mb-2">Today's Expense</p>
                <p className="text-4xl font-bold text-gray-900">Rs. {summary.todayExpense.toFixed(2)}</p>
                <div className="mt-3 h-2 bg-gradient-to-r from-red-500 to-rose-500 rounded-full"></div>
              </div>
            </div>
          </div>

          <div className={`relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl`}>
            <div className={`absolute inset-0 bg-gradient-to-br ${summary.todayProfit >= 0 ? 'from-blue-400/20 to-indigo-600/20' : 'from-orange-400/20 to-amber-600/20'}`}></div>
            <div className="relative p-8">
              <div className="flex items-center justify-between mb-6">
                <div className={`bg-gradient-to-r ${summary.todayProfit >= 0 ? 'from-blue-500 to-indigo-500' : 'from-orange-500 to-amber-500'} rounded-3xl p-4 shadow-xl`}>
                  {summary.todayProfit >= 0 ? <ArrowUpRight className="h-8 w-8 text-white" /> : <ArrowDownRight className="h-8 w-8 text-white" />}
                </div>
                <div className={`${summary.todayProfit >= 0 ? 'bg-blue-500/20 text-blue-700' : 'bg-orange-500/20 text-orange-700'} rounded-full px-4 py-2`}>
                  <span className="text-sm font-semibold">{summary.todayProfit >= 0 ? '+15.2%' : '-5.8%'}</span>
                </div>
              </div>
              <div>
                <p className={`text-gray-600 text-base font-medium mb-2`}>Today's Profit</p>
                <p className="text-4xl font-bold text-gray-900">Rs. {summary.todayProfit.toFixed(2)}</p>
                <div className={`mt-3 h-2 bg-gradient-to-r ${summary.todayProfit >= 0 ? 'from-blue-500 to-indigo-500' : 'from-orange-500 to-amber-500'} rounded-full`}></div>
              </div>
            </div>
          </div>
        </div>

        {/* Payment Method Breakdown */}
        <div className="border-t border-indigo-200 pt-8">
          <h4 className="text-xl font-semibold text-gray-800 mb-6 flex items-center">
            <CreditCard className="h-6 w-6 text-indigo-600 mr-3" />
            Payment Method Breakdown
          </h4>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-6">
            <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl hover:shadow-3xl transition-shadow duration-300">
              <div className="absolute inset-0 bg-gradient-to-br from-emerald-400/20 to-green-600/20"></div>
              <div className="relative p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className="bg-gradient-to-r from-emerald-500 to-green-500 rounded-2xl p-3 shadow-xl">
                    <Banknote className="h-6 w-6 text-white" />
                  </div>
                  <div className="bg-emerald-500/20 rounded-full px-3 py-1">
                    <span className="text-emerald-700 text-sm font-semibold">45%</span>
                  </div>
                </div>
                <div>
                  <p className="text-gray-600 text-sm font-medium mb-2">Cash</p>
                  <p className="text-2xl font-bold text-gray-900">Rs. {summary.todayCashIncome.toFixed(2)}</p>
                  <div className="mt-3 h-1 bg-gradient-to-r from-emerald-500 to-green-500 rounded-full"></div>
                </div>
              </div>
            </div>

            <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl hover:shadow-3xl transition-shadow duration-300">
              <div className="absolute inset-0 bg-gradient-to-br from-purple-400/20 to-pink-600/20"></div>
              <div className="relative p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className="bg-gradient-to-r from-purple-500 to-pink-500 rounded-2xl p-3 shadow-xl">
                    <CreditCard className="h-6 w-6 text-white" />
                  </div>
                  <div className="bg-purple-500/20 rounded-full px-3 py-1">
                    <span className="text-purple-700 text-sm font-semibold">30%</span>
                  </div>
                </div>
                <div>
                  <p className="text-gray-600 text-sm font-medium mb-2">UPI</p>
                  <p className="text-2xl font-bold text-gray-900">Rs. {summary.todayUPIIncome.toFixed(2)}</p>
                  <div className="mt-3 h-1 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full"></div>
                </div>
              </div>
            </div>

            <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl hover:shadow-3xl transition-shadow duration-300">
              <div className="absolute inset-0 bg-gradient-to-br from-blue-400/20 to-cyan-600/20"></div>
              <div className="relative p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className="bg-gradient-to-r from-blue-500 to-cyan-500 rounded-2xl p-3 shadow-xl">
                    <CreditCard className="h-6 w-6 text-white" />
                  </div>
                  <div className="bg-blue-500/20 rounded-full px-3 py-1">
                    <span className="text-blue-700 text-sm font-semibold">20%</span>
                  </div>
                </div>
                <div>
                  <p className="text-gray-600 text-sm font-medium mb-2">Credit Card</p>
                  <p className="text-2xl font-bold text-gray-900">Rs. {summary.todayCreditCardIncome.toFixed(2)}</p>
                  <div className="mt-3 h-1 bg-gradient-to-r from-blue-500 to-cyan-500 rounded-full"></div>
                </div>
              </div>
            </div>

            <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl hover:shadow-3xl transition-shadow duration-300">
              <div className="absolute inset-0 bg-gradient-to-br from-orange-400/20 to-amber-600/20"></div>
              <div className="relative p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className="bg-gradient-to-r from-orange-500 to-amber-500 rounded-2xl p-3 shadow-xl">
                    <DollarSign className="h-6 w-6 text-white" />
                  </div>
                  <div className="bg-orange-500/20 rounded-full px-3 py-1">
                    <span className="text-orange-700 text-sm font-semibold">5%</span>
                  </div>
                </div>
                <div>
                  <p className="text-gray-600 text-sm font-medium mb-2">Bank Transfer</p>
                  <p className="text-2xl font-bold text-gray-900">Rs. {summary.todayBankTransferIncome.toFixed(2)}</p>
                  <div className="mt-3 h-1 bg-gradient-to-r from-orange-500 to-amber-500 rounded-full"></div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Overall Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-gradient-to-br from-green-500 to-green-600 rounded-xl p-6 text-white shadow-lg">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-green-100 text-sm font-medium">Total Income</p>
              <p className="text-2xl font-bold">Rs. {summary.totalIncome.toFixed(2)}</p>
            </div>
            <div className="bg-white/20 rounded-full p-3">
              <TrendingUp className="h-6 w-6" />
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-red-500 to-red-600 rounded-xl p-6 text-white shadow-lg">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-red-100 text-sm font-medium">Total Expense</p>
              <p className="text-2xl font-bold">Rs. {summary.totalExpense.toFixed(2)}</p>
            </div>
            <div className="bg-white/20 rounded-full p-3">
              <TrendingDown className="h-6 w-6" />
            </div>
          </div>
        </div>

        <div className={`bg-gradient-to-br ${summary.profit >= 0 ? 'from-blue-500 to-blue-600' : 'from-orange-500 to-orange-600'} rounded-xl p-6 text-white shadow-lg`}>
          <div className="flex items-center justify-between">
            <div>
              <p className={`${summary.profit >= 0 ? 'text-blue-100' : 'text-orange-100'} text-sm font-medium`}>Net Profit</p>
              <p className="text-2xl font-bold">Rs. {summary.profit.toFixed(2)}</p>
              <p className={`text-xs mt-1 ${summary.profit >= 0 ? 'text-blue-100' : 'text-orange-100'}`}>
                {summary.profitMargin.toFixed(1)}% margin
              </p>
            </div>
            <div className="bg-white/20 rounded-full p-3">
              {summary.profit >= 0 ? <ArrowUpRight className="h-6 w-6" /> : <ArrowDownRight className="h-6 w-6" />}
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-purple-500 to-purple-600 rounded-xl p-6 text-white shadow-lg">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-purple-100 text-sm font-medium">Transactions</p>
              <p className="text-2xl font-bold">{summary.totalTransactions}</p>
              <p className="text-xs text-purple-100 mt-1">
                Avg: Rs. {summary.averageTransaction.toFixed(2)}
              </p>
            </div>
            <div className="bg-white/20 rounded-full p-3">
              <Receipt className="h-6 w-6" />
            </div>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <div className="flex items-center mb-4">
          <Filter className="h-5 w-5 text-gray-600 mr-2" />
          <h3 className="text-lg font-semibold text-gray-800">Filters</h3>
        </div>
        
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Year</label>
            <select
              value={filterYear}
              onChange={(e) => setFilterYear(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="2024">2024</option>
              <option value="2025">2025</option>
              <option value="2026">2026</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Month</label>
            <select
              value={filterMonth}
              onChange={(e) => setFilterMonth(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="">All Months</option>
              <option value="01">January</option>
              <option value="02">February</option>
              <option value="03">March</option>
              <option value="04">April</option>
              <option value="05">May</option>
              <option value="06">June</option>
              <option value="07">July</option>
              <option value="08">August</option>
              <option value="09">September</option>
              <option value="10">October</option>
              <option value="11">November</option>
              <option value="12">December</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
            <input
              type="date"
              value={filterDate}
              onChange={(e) => setFilterDate(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Search</label>
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search..."
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              {activeTab === 'income' ? 'Payment Method' : 'Category'}
            </label>
            <select
              value={activeTab === 'income' ? filterPaymentMethod : filterCategory}
              onChange={(e) => {
                if (activeTab === 'income') {
                  setFilterPaymentMethod(e.target.value)
                } else {
                  setFilterCategory(e.target.value)
                }
              }}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="all">All</option>
              {activeTab === 'income' ? (
                <>
                  <option value="cash">Cash</option>
                  <option value="upi">UPI</option>
                  <option value="credit_card">Credit Card</option>
                  <option value="bank_transfer">Bank Transfer</option>
                </>
              ) : (
                getUniqueCategories().map(category => (
                  <option key={category} value={category}>{category}</option>
                ))
              )}
            </select>
          </div>

          <div className="lg:col-span-3 xl:col-span-6 flex flex-wrap gap-2 items-end">
            <button
              onClick={() => {
                const today = new Date()
                setFilterMonth((today.getMonth() + 1).toString().padStart(2, '0'))
                setFilterYear(today.getFullYear().toString())
                setFilterDate('')
              }}
              className="bg-blue-100 text-blue-700 px-4 py-2 rounded-lg hover:bg-blue-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <Calendar className="h-4 w-4 mr-2" />
              This Month
            </button>
            <button
              onClick={() => {
                const today = new Date()
                setFilterMonth('')
                setFilterYear(today.getFullYear().toString())
                setFilterDate('')
              }}
              className="bg-green-100 text-green-700 px-4 py-2 rounded-lg hover:bg-green-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <TrendingUp className="h-4 w-4 mr-2" />
              This Year
            </button>
            <button
              onClick={clearFilters}
              className="bg-gray-100 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <RefreshCw className="h-4 w-4 mr-2" />
              Clear
            </button>
            <button
              onClick={exportData}
              className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <Download className="h-4 w-4 mr-2" />
              Export
            </button>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200">
        <div className="border-b border-gray-200">
          <nav className="flex -mb-px">
            <button
              onClick={() => setActiveTab('income')}
              className={`py-4 px-6 border-b-2 font-medium text-sm transition-colors ${
                activeTab === 'income'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              }`}
            >
              <div className="flex items-center">
                <TrendingUp className="h-4 w-4 mr-2" />
                Income ({bills.length})
              </div>
            </button>
            <button
              onClick={() => setActiveTab('expense')}
              className={`py-4 px-6 border-b-2 font-medium text-sm transition-colors ${
                activeTab === 'expense'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              }`}
            >
              <div className="flex items-center">
                <TrendingDown className="h-4 w-4 mr-2" />
                Expenses ({expenses.length})
              </div>
            </button>
          </nav>
        </div>

        {/* Tab Content */}
        <div className="p-6">
          {activeTab === 'income' ? (
            <IncomeTable bills={bills} />
          ) : (
            <ExpenseTable expenses={expenses} />
          )}
        </div>
      </div>
    </div>
  )
}

