import { useState, useEffect } from 'react'
import { Link } from 'react-router-dom'
import { 
  Bookmark as BookmarkIcon, 
  Plus, 
  Search, 
  Filter, 
  Grid, 
  List, 
  Star, 
  ExternalLink, 
  Edit, 
  Trash2, 
  X, 
  Tag,
  Globe,
  Heart
} from 'lucide-react'
import toast from 'react-hot-toast'
import BookmarkCard from '../components/BookmarkCard'
import BookmarkModal from '../components/BookmarkModal'

const Bookmarks = () => {
  const [bookmarks, setBookmarks] = useState([])
  const [filteredBookmarks, setFilteredBookmarks] = useState([])
  const [categories, setCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedCategory, setSelectedCategory] = useState('')
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false)
  const [viewMode, setViewMode] = useState('grid') // 'grid' or 'list'
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingBookmark, setEditingBookmark] = useState(null)
  const [showCategoryFilter, setShowCategoryFilter] = useState(false)

  useEffect(() => {
    fetchBookmarks()
    fetchCategories()
  }, [])

  useEffect(() => {
    filterBookmarks()
  }, [bookmarks, searchTerm, selectedCategory, showFavoritesOnly])

  const fetchBookmarks = async () => {
    try {
      setLoading(true)
      const response = await fetch('/api/bookmarks')
      if (!response.ok) throw new Error('Failed to fetch bookmarks')
      const data = await response.json()
      setBookmarks(data.bookmarks)
    } catch (error) {
      console.error('Error fetching bookmarks:', error)
      toast.error('Failed to load bookmarks')
    } finally {
      setLoading(false)
    }
  }

  const fetchCategories = async () => {
    try {
      const response = await fetch('/api/bookmarks/categories/list')
      if (!response.ok) throw new Error('Failed to fetch categories')
      const data = await response.json()
      setCategories(data)
    } catch (error) {
      console.error('Error fetching categories:', error)
    }
  }

  const filterBookmarks = () => {
    let filtered = [...bookmarks]

    // Filter by search term
    if (searchTerm) {
      filtered = filtered.filter(bookmark =>
        bookmark.serviceName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        bookmark.description?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        bookmark.url.toLowerCase().includes(searchTerm.toLowerCase()) ||
        bookmark.tags?.some(tag => tag.toLowerCase().includes(searchTerm.toLowerCase()))
      )
    }

    // Filter by category
    if (selectedCategory) {
      filtered = filtered.filter(bookmark => bookmark.category === selectedCategory)
    }

    // Filter by favorites
    if (showFavoritesOnly) {
      filtered = filtered.filter(bookmark => bookmark.isFavorite)
    }

    setFilteredBookmarks(filtered)
  }

  const handleAddBookmark = () => {
    setEditingBookmark(null)
    setIsModalOpen(true)
  }

  const handleEditBookmark = (bookmark) => {
    setEditingBookmark(bookmark)
    setIsModalOpen(true)
  }

  const handleDeleteBookmark = async (bookmarkId) => {
    if (!confirm('Are you sure you want to delete this bookmark?')) return

    try {
      const response = await fetch(`/api/bookmarks/${bookmarkId}`, {
        method: 'DELETE'
      })
      
      if (!response.ok) throw new Error('Failed to delete bookmark')
      
      setBookmarks(bookmarks.filter(b => b._id !== bookmarkId))
      toast.success('Bookmark deleted successfully')
    } catch (error) {
      console.error('Error deleting bookmark:', error)
      toast.error('Failed to delete bookmark')
    }
  }

  const handleToggleFavorite = async (bookmarkId) => {
    try {
      const response = await fetch(`/api/bookmarks/${bookmarkId}/favorite`, {
        method: 'PATCH'
      })
      
      if (!response.ok) throw new Error('Failed to toggle favorite')
      
      const updatedBookmark = await response.json()
      setBookmarks(bookmarks.map(b => b._id === bookmarkId ? updatedBookmark : b))
    } catch (error) {
      console.error('Error toggling favorite:', error)
      toast.error('Failed to update favorite status')
    }
  }

  const handleBookmarkSave = (savedBookmark) => {
    if (editingBookmark) {
      setBookmarks(bookmarks.map(b => b._id === savedBookmark._id ? savedBookmark : b))
      toast.success('Bookmark updated successfully')
    } else {
      setBookmarks([...bookmarks, savedBookmark])
      toast.success('Bookmark added successfully')
    }
    setIsModalOpen(false)
    setEditingBookmark(null)
  }

  const handleUrlClick = (url) => {
    window.open(url, '_blank', 'noopener,noreferrer')
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100">
      {/* Header */}
      <div className="bg-white shadow-sm border-b border-gray-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="p-3 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl shadow-lg shadow-blue-500/30">
                <BookmarkIcon className="h-6 w-6 text-white" />
              </div>
              <div>
                <h1 className="text-2xl font-bold text-gray-900">Bookmarks</h1>
                <p className="text-sm text-gray-500">Manage your favorite websites and services</p>
              </div>
            </div>
            <button
              onClick={handleAddBookmark}
              className="bg-gradient-to-r from-blue-500 to-blue-600 text-white px-4 py-2 rounded-lg hover:from-blue-600 hover:to-blue-700 transition-all duration-200 flex items-center space-x-2 shadow-md hover:shadow-lg transform hover:scale-105"
            >
              <Plus className="h-5 w-5" />
              <span>Add Bookmark</span>
            </button>
          </div>
        </div>
      </div>

      {/* Filters and Search */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            {/* Search */}
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                placeholder="Search bookmarks..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>

            {/* Category Filter */}
            <div className="relative">
              <button
                onClick={() => setShowCategoryFilter(!showCategoryFilter)}
                className="w-full flex items-center justify-between px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
              >
                <span className="flex items-center space-x-2">
                  <Filter className="h-4 w-4 text-gray-400" />
                  <span className={selectedCategory ? 'text-gray-900' : 'text-gray-500'}>
                    {selectedCategory || 'All Categories'}
                  </span>
                </span>
                <Tag className="h-4 w-4 text-gray-400" />
              </button>
              
              {showCategoryFilter && (
                <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-10 max-h-48 overflow-y-auto">
                  <button
                    onClick={() => {
                      setSelectedCategory('')
                      setShowCategoryFilter(false)
                    }}
                    className="w-full text-left px-4 py-2 hover:bg-gray-50 transition-colors text-sm"
                  >
                    All Categories
                  </button>
                  {categories.map(category => (
                    <button
                      key={category}
                      onClick={() => {
                        setSelectedCategory(category)
                        setShowCategoryFilter(false)
                      }}
                      className="w-full text-left px-4 py-2 hover:bg-gray-50 transition-colors text-sm"
                    >
                      {category}
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Favorites Filter */}
            <button
              onClick={() => setShowFavoritesOnly(!showFavoritesOnly)}
              className={`flex items-center justify-center space-x-2 px-4 py-2 rounded-lg transition-colors ${
                showFavoritesOnly 
                  ? 'bg-yellow-100 text-yellow-700 border border-yellow-300' 
                  : 'bg-gray-50 text-gray-700 border border-gray-300 hover:bg-gray-100'
              }`}
            >
              <Heart className={`h-4 w-4 ${showFavoritesOnly ? 'fill-current' : ''}`} />
              <span>Favorites</span>
            </button>

            {/* View Mode */}
            <div className="flex items-center justify-center space-x-2 bg-gray-50 rounded-lg p-1">
              <button
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded-md transition-colors ${
                  viewMode === 'grid' 
                    ? 'bg-white text-blue-600 shadow-sm' 
                    : 'text-gray-600 hover:text-gray-900'
                }`}
              >
                <Grid className="h-4 w-4" />
              </button>
              <button
                onClick={() => setViewMode('list')}
                className={`p-2 rounded-md transition-colors ${
                  viewMode === 'list' 
                    ? 'bg-white text-blue-600 shadow-sm' 
                    : 'text-gray-600 hover:text-gray-900'
                }`}
              >
                <List className="h-4 w-4" />
              </button>
            </div>
          </div>

          {/* Active Filters */}
          {(selectedCategory || showFavoritesOnly || searchTerm) && (
            <div className="mt-4 flex items-center space-x-2 flex-wrap">
              {selectedCategory && (
                <span className="inline-flex items-center space-x-1 bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-sm">
                  <Tag className="h-3 w-3" />
                  <span>{selectedCategory}</span>
                  <button
                    onClick={() => setSelectedCategory('')}
                    className="ml-1 hover:text-blue-900"
                  >
                    <X className="h-3 w-3" />
                  </button>
                </span>
              )}
              {showFavoritesOnly && (
                <span className="inline-flex items-center space-x-1 bg-yellow-100 text-yellow-700 px-3 py-1 rounded-full text-sm">
                  <Heart className="h-3 w-3 fill-current" />
                  <span>Favorites</span>
                  <button
                    onClick={() => setShowFavoritesOnly(false)}
                    className="ml-1 hover:text-yellow-900"
                  >
                    <X className="h-3 w-3" />
                  </button>
                </span>
              )}
              {searchTerm && (
                <span className="inline-flex items-center space-x-1 bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-sm">
                  <Search className="h-3 w-3" />
                  <span>{searchTerm}</span>
                  <button
                    onClick={() => setSearchTerm('')}
                    className="ml-1 hover:text-gray-900"
                  >
                    <X className="h-3 w-3" />
                  </button>
                </span>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Bookmarks Grid/List */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pb-8">
        {loading ? (
          <div className="flex items-center justify-center py-12">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
          </div>
        ) : filteredBookmarks.length === 0 ? (
          <div className="text-center py-12">
            <BookmarkIcon className="mx-auto h-12 w-12 text-gray-400" />
            <h3 className="mt-2 text-sm font-medium text-gray-900">No bookmarks found</h3>
            <p className="mt-1 text-sm text-gray-500">
              {bookmarks.length === 0 
                ? 'Get started by adding your first bookmark.' 
                : 'Try adjusting your search or filters.'}
            </p>
            {bookmarks.length === 0 && (
              <div className="mt-6">
                <button
                  onClick={handleAddBookmark}
                  className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                >
                  <Plus className="h-4 w-4 mr-2" />
                  Add Your First Bookmark
                </button>
              </div>
            )}
          </div>
        ) : (
          <div className={
            viewMode === 'grid' 
              ? 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6'
              : 'space-y-4'
          }>
            {filteredBookmarks.map((bookmark) => (
              <BookmarkCard
                key={bookmark._id}
                bookmark={bookmark}
                viewMode={viewMode}
                onEdit={handleEditBookmark}
                onDelete={handleDeleteBookmark}
                onToggleFavorite={handleToggleFavorite}
                onUrlClick={handleUrlClick}
              />
            ))}
          </div>
        )}
      </div>

      {/* Bookmark Modal */}
      {isModalOpen && (
        <BookmarkModal
          bookmark={editingBookmark}
          categories={categories}
          onSave={handleBookmarkSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingBookmark(null)
          }}
        />
      )}
    </div>
  )
}

export default Bookmarks
