import { Link, useLocation, useNavigate } from 'react-router-dom'
import { useState, useEffect } from 'react'
import { 
  LayoutDashboard, 
  Users, 
  UserCog, 
  FileText, 
  Wrench, 
  BarChart3,
  Plus,
  Home,
  Settings,
  Calendar,
  ArrowLeft,
  Printer,
  ChevronDown,
  IndianRupee,
  Receipt,
  PieChart,
  X,
  TrendingUp,
  TrendingDown,
  Bell,
  Package,
  LogOut,
  User,
  Menu,
  Bookmark as BookmarkIcon
} from 'lucide-react'

const Layout = ({ children }) => {
  const location = useLocation()
  const navigate = useNavigate()
  const [machinesDropdownOpen, setMachinesDropdownOpen] = useState(false)
  const [financialDropdownOpen, setFinancialDropdownOpen] = useState(false)
  const [accountsDropdownOpen, setAccountsDropdownOpen] = useState(false)
  const [currentUser, setCurrentUser] = useState(null)
  const [userDropdownOpen, setUserDropdownOpen] = useState(false)
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false)
  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    // Get user data from localStorage
    const userData = localStorage.getItem('user')
    if (userData) {
      setCurrentUser(JSON.parse(userData))
    }

    // Check if mobile
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 1024)
      if (window.innerWidth >= 1024) {
        setMobileMenuOpen(false)
      }
    }
    
    checkMobile()
    window.addEventListener('resize', checkMobile)
    return () => window.removeEventListener('resize', checkMobile)
  }, [])

  const handleLogout = () => {
    localStorage.removeItem('authToken')
    localStorage.removeItem('user')
    navigate('/login')
  }

  const navigation = [
    { name: 'Dashboard', href: '/', icon: LayoutDashboard, color: 'blue' },
    { name: 'Customer Management', href: '/customer-management', icon: UserCog, color: 'green' },
    { name: 'Reminder Management', href: '/reminder-management', icon: Bell, color: 'rose' },
    { name: 'Bookmarks', href: '/bookmarks', icon: BookmarkIcon, color: 'purple' },
    { name: 'Billing', href: '/billing', icon: IndianRupee, color: 'amber' },
    { name: 'Machines', href: '/machines', icon: Printer, color: 'violet' },
    { name: 'Settings', href: '/settings', icon: Settings, color: 'indigo' },
  ]

  const billingMenuItems = [
    { name: 'New Bill', href: '/new-bill', icon: Plus },
    { name: 'Expense Management', href: '/expense-management', icon: FileText },
    { name: 'Expense Settings', href: '/expense-settings', icon: Settings },
    { name: 'Profit & Loss', href: '/balance-sheet', icon: BarChart3 }
  ]

  const financeMenuItems = [
    { name: 'New Bill', href: '/new-bill', icon: Plus },
    { name: 'Expense Management', href: '/expense-management', icon: FileText },
    { name: 'Expense Settings', href: '/expense-settings', icon: Settings },
    { name: 'Profit & Loss', href: '/balance-sheet', icon: BarChart3 }
  ]

  const quickActions = [
    { name: 'Add Customer', href: '/customers?action=add', icon: Plus },
    { name: 'Add Machine', href: '/machines?tab=machines&action=add', icon: Plus },
    { name: 'Add Reading', href: '/machines?tab=readings&action=add', icon: Plus },
    { name: 'Schedule Maintenance', href: '/machines?tab=maintenance&action=add', icon: Plus },
    { name: 'Categories', href: '/settings?tab=categories', icon: Package },
  ]

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 flex">
      {/* Mobile Menu Overlay */}
      {isMobile && mobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-40 lg:hidden"
          onClick={() => setMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar - Fixed on desktop, sliding on mobile */}
      <div className={`${
        isMobile 
          ? `fixed left-0 top-0 h-screen z-50 transform transition-transform duration-300 ease-in-out ${
              mobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
            }`
          : 'w-72 bg-gradient-to-b from-slate-900 via-slate-800 to-slate-900 shadow-2xl border-r border-slate-700 fixed left-0 top-0 h-screen z-40'
      } bg-gradient-to-b from-slate-900 via-slate-800 to-slate-900 shadow-2xl border-r border-slate-700`}>
        <div className="p-6 border-b border-slate-700">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="p-3 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl shadow-lg shadow-blue-500/30">
                <Settings className="h-6 w-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-white">Maintenance System</h1>
                <p className="text-sm text-slate-400">Printer Management</p>
              </div>
            </div>
            {isMobile && (
              <button
                onClick={() => setMobileMenuOpen(false)}
                className="text-slate-400 hover:text-white transition-colors"
              >
                <X className="h-6 w-6" />
              </button>
            )}
          </div>
        </div>
        
        <nav className="mt-6 px-4">
          <div className="mb-6">
            <h3 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
              <div className="w-1 h-3 bg-blue-400 rounded-full"></div>
              Main Menu
              <div className="w-1 h-3 bg-blue-400 rounded-full"></div>
            </h3>
            <div className="space-y-3">
              {navigation.map((item) => {
                const isActive = location.pathname === item.href
                const colorClasses = {
                  blue: isActive 
                    ? 'bg-gradient-to-r from-blue-500 to-blue-600 text-white shadow-lg shadow-blue-500/30 border border-blue-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-blue-500 hover:to-blue-600 hover:text-white hover:shadow-lg hover:shadow-blue-500/30 border border-slate-600 hover:border-blue-400',
                  green: isActive 
                    ? 'bg-gradient-to-r from-green-500 to-green-600 text-white shadow-lg shadow-green-500/30 border border-green-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-green-500 hover:to-green-600 hover:text-white hover:shadow-lg hover:shadow-green-500/30 border border-slate-600 hover:border-green-400',
                  emerald: isActive 
                    ? 'bg-gradient-to-r from-emerald-500 to-emerald-600 text-white shadow-lg shadow-emerald-500/30 border border-emerald-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-emerald-500 hover:to-emerald-600 hover:text-white hover:shadow-lg hover:shadow-emerald-500/30 border border-slate-600 hover:border-emerald-400',
                  violet: isActive 
                    ? 'bg-gradient-to-r from-violet-500 to-violet-600 text-white shadow-lg shadow-violet-500/30 border border-violet-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-violet-500 hover:to-violet-600 hover:text-white hover:shadow-lg hover:shadow-violet-500/30 border border-slate-600 hover:border-violet-400',
                  amber: isActive 
                    ? 'bg-gradient-to-r from-amber-500 to-amber-600 text-white shadow-lg shadow-amber-500/30 border border-amber-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-amber-500 hover:to-amber-600 hover:text-white hover:shadow-lg hover:shadow-amber-500/30 border border-slate-600 hover:border-amber-400',
                  rose: isActive 
                    ? 'bg-gradient-to-r from-rose-500 to-rose-600 text-white shadow-lg shadow-rose-500/30 border border-rose-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-rose-500 hover:to-rose-600 hover:text-white hover:shadow-lg hover:shadow-rose-500/30 border border-slate-600 hover:border-rose-400',
                  indigo: isActive 
                    ? 'bg-gradient-to-r from-indigo-500 to-indigo-600 text-white shadow-lg shadow-indigo-500/30 border border-indigo-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-indigo-500 hover:to-indigo-600 hover:text-white hover:shadow-lg hover:shadow-indigo-500/30 border border-slate-600 hover:border-indigo-400',
                  purple: isActive 
                    ? 'bg-gradient-to-r from-purple-500 to-purple-600 text-white shadow-lg shadow-purple-500/30 border border-purple-400' 
                    : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-purple-500 hover:to-purple-600 hover:text-white hover:shadow-lg hover:shadow-purple-500/30 border border-slate-600 hover:border-purple-400'
                }
                
                return (
                  <div key={item.name}>
                    {item.name === 'Machines' ? (
                      <Link
                        to="/machines"
                        className={`group flex items-center px-4 py-3 text-sm font-medium rounded-xl transition-all duration-300 transform hover:scale-105 hover:shadow-lg ${
                          location.pathname.startsWith('/machines')
                            ? 'bg-gradient-to-r from-violet-500 to-violet-600 text-white shadow-lg shadow-violet-500/30 border border-violet-400' 
                            : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-violet-500 hover:to-violet-600 hover:text-white hover:shadow-lg hover:shadow-violet-500/30 border border-slate-600 hover:border-violet-400'
                        }`}
                      >
                        <item.icon
                          className={`${
                            location.pathname.startsWith('/machines')
                              ? 'text-white drop-shadow-sm' : 'text-slate-400 group-hover:text-white drop-shadow-sm'
                          } mr-3 h-5 w-5 transition-all duration-300`}
                        />
                        <span className={`${
                          location.pathname.startsWith('/machines')
                            ? 'font-semibold text-white' : 'text-slate-300 group-hover:text-white'
                        }`}>{item.name}</span>
                      </Link>
                    ) : item.name === 'Billing' ? (
                      <Link
                        to="/financial"
                        className={`group flex items-center px-4 py-3 text-sm font-medium rounded-xl transition-all duration-300 transform hover:scale-105 hover:shadow-lg ${
                          location.pathname.startsWith('/financial')
                            ? 'bg-gradient-to-r from-amber-500 to-amber-600 text-white shadow-lg shadow-amber-500/30 border border-amber-400' 
                            : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-amber-500 hover:to-amber-600 hover:text-white hover:shadow-lg hover:shadow-amber-500/30 border border-slate-600 hover:border-amber-400'
                        }`}
                      >
                        <item.icon
                          className={`${
                            location.pathname.startsWith('/financial')
                              ? 'text-white drop-shadow-sm' : 'text-slate-400 group-hover:text-white drop-shadow-sm'
                          } mr-3 h-5 w-5 transition-all duration-300`}
                        />
                        <span className={`${
                          location.pathname.startsWith('/financial')
                            ? 'font-semibold text-white' : 'text-slate-300 group-hover:text-white'
                        }`}>{item.name}</span>
                      </Link>
                    ) : item.name === 'Settings' ? (
                      <Link
                        to="/settings"
                        className={`group w-full flex items-center justify-between px-4 py-3 text-sm font-medium rounded-xl transition-all duration-300 transform hover:scale-105 ${
                          location.pathname === '/settings'
                            ? 'bg-gradient-to-r from-indigo-500 to-indigo-600 text-white shadow-lg shadow-indigo-500/30 border border-indigo-400' 
                            : 'bg-gradient-to-r from-slate-700 to-slate-800 text-slate-300 hover:from-indigo-500 hover:to-indigo-600 hover:text-white hover:shadow-lg hover:shadow-indigo-500/30 border border-slate-600 hover:border-indigo-400'
                        }`}
                      >
                        <div className="flex items-center gap-3">
                          <item.icon className={`${
                            location.pathname === '/settings'
                              ? 'text-white drop-shadow-sm' : 'text-slate-400 group-hover:text-white drop-shadow-sm'
                          } h-5 w-5 transition-all duration-300`} />
                          <span className={`${
                            location.pathname === '/settings'
                              ? 'font-semibold text-white' : 'text-slate-300 group-hover:text-white'
                          }`}>{item.name}</span>
                        </div>
                      </Link>
                    ) : (
                      <Link
                        to={item.href}
                        onClick={() => {
                          if (isMobile) setMobileMenuOpen(false)
                        }}
                        className={`group flex items-center px-4 py-3 text-sm font-medium rounded-xl transition-all duration-300 transform hover:scale-105 hover:shadow-lg ${colorClasses[item.color]}`}
                      >
                        <item.icon
                          className={`${
                            isActive ? 'text-white drop-shadow-sm' : 'text-slate-400 group-hover:text-white drop-shadow-sm'
                          } mr-3 h-5 w-5 transition-all duration-300`}
                        />
                        <span className={`${isActive ? 'font-semibold text-white' : 'text-slate-300 group-hover:text-white'}`}>{item.name}</span>
                        {isActive && (
                          <div className="ml-auto w-2 h-2 bg-white rounded-full animate-pulse"></div>
                        )}
                      </Link>
                    )}
                  </div>
                 
                )
                })}
            </div>
          </div>

         
        </nav>
      </div>

      {/* Main Content */}
      <div className={`flex-1 flex flex-col ${
        isMobile ? 'ml-0' : 'ml-72'
      }`}>
        {/* Header - Fixed */}
        <header className={`bg-white shadow-sm border-b border-slate-200 fixed top-0 z-30 ${
          isMobile ? 'left-0 right-0' : 'left-72 right-0'
        }`}>
          <div className="px-4 lg:px-6 py-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-4">
                {/* Mobile Menu Toggle */}
                {isMobile && (
                  <button
                    onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
                    className="text-slate-600 hover:text-slate-900 transition-colors"
                  >
                    <Menu className="h-6 w-6" />
                  </button>
                )}
                <div>
                  <h2 className="text-lg lg:text-xl font-semibold text-slate-900">
                    {navigation.find(item => item.href === location.pathname)?.name || 'Dashboard'}
                  </h2>
                  <p className="text-sm text-slate-500 mt-1 hidden lg:block">Manage your business operations efficiently</p>
                </div>
              </div>
              
              <div className="flex items-center space-x-2 lg:space-x-3">
                {/* Back to Home Button */}
                <Link
                  to="/"
                  className={`${
                    location.pathname === '/' 
                      ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                      : 'bg-gradient-to-r from-blue-500 to-blue-600 text-white hover:from-blue-600 hover:to-blue-700'
                  } px-3 lg:px-4 py-2 rounded-lg transition-all duration-200 flex items-center space-x-1 lg:space-x-2 shadow-md`}
                >
                  <Home className="h-4 w-4" />
                  <span className="hidden sm:inline">Home</span>
                </Link>
                
                
                {/* User Dropdown */}
                <div className="relative">
                  <button
                    onClick={() => setUserDropdownOpen(!userDropdownOpen)}
                    className="flex items-center space-x-2 lg:space-x-3 p-2 rounded-lg hover:bg-slate-100 transition-colors"
                  >
                    <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full flex items-center justify-center text-white font-semibold text-sm">
                      {currentUser?.avatar || 'U'}
                    </div>
                    <div className="text-left hidden lg:block">
                      <p className="text-sm font-medium text-slate-900">{currentUser?.name || 'User'}</p>
                      <p className="text-xs text-slate-500 capitalize">{currentUser?.role || 'Guest'}</p>
                    </div>
                    <ChevronDown className={`h-4 w-4 text-slate-400 transition-transform ${userDropdownOpen ? 'rotate-180' : ''}`} />
                  </button>

                  {userDropdownOpen && (
                    <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-slate-200 py-2 z-50">
                      <div className="px-4 py-2 border-b border-slate-100">
                        <p className="text-sm font-medium text-slate-900">{currentUser?.name || 'User'}</p>
                        <p className="text-xs text-slate-500">{currentUser?.email || 'No email'}</p>
                      </div>
                      <button
                        onClick={() => {
                          navigate('/settings')
                          setUserDropdownOpen(false)
                          if (isMobile) setMobileMenuOpen(false)
                        }}
                        className="w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100 transition-colors flex items-center space-x-2"
                      >
                        <User className="h-4 w-4" />
                        <span>User Profile</span>
                      </button>
                      <button
                        onClick={() => {
                          navigate('/settings')
                          setUserDropdownOpen(false)
                          if (isMobile) setMobileMenuOpen(false)
                        }}
                        className="w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100 transition-colors flex items-center space-x-2"
                      >
                        <Settings className="h-4 w-4" />
                        <span>Settings</span>
                      </button>
                      <div className="border-t border-slate-100 mt-2 pt-2">
                        <button
                          onClick={() => {
                            handleLogout()
                            setUserDropdownOpen(false)
                            if (isMobile) setMobileMenuOpen(false)
                          }}
                          className="w-full px-4 py-2 text-left text-sm text-red-600 hover:bg-red-50 transition-colors flex items-center space-x-2"
                        >
                          <LogOut className="h-4 w-4" />
                          <span>Logout</span>
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </header>

        {/* Page Content - Scrollable */}
        <main className="flex-1 p-4 lg:p-6 mt-16 overflow-y-auto">
          {children}
        </main>
      </div>
    </div>
  )
}

export default Layout
