import { useState } from 'react'
import { 
  ChevronRight, 
  ArrowUp, 
  ArrowDown, 
  TrendingUp, 
  TrendingDown,
  Star,
  Heart,
  Bookmark,
  Share2,
  MoreVertical,
  ExternalLink
} from 'lucide-react'

const Card = ({ 
  children,
  variant = 'default', // 'default', 'gradient', 'glass', 'elevated', 'minimal'
  size = 'medium', // 'small', 'medium', 'large'
  hover = true,
  clickable = false,
  onClick,
  className = '',
  header,
  footer,
  badge,
  icon,
  actions
}) => {
  const [isHovered, setIsHovered] = useState(false)

  const baseClasses = 'relative transition-all duration-300 rounded-2xl border'
  
  const variantClasses = {
    default: 'bg-white border-gray-200 shadow-lg hover:shadow-xl',
    gradient: 'bg-gradient-to-br from-white to-gray-50 border-gray-100 shadow-xl hover:shadow-2xl',
    glass: 'bg-white/80 backdrop-blur-lg border-white/20 shadow-xl hover:shadow-2xl',
    elevated: 'bg-gradient-to-br from-gray-50 to-white border-gray-200 shadow-2xl hover:shadow-3xl',
    minimal: 'bg-white border-gray-100 shadow-sm hover:shadow-md'
  }

  const sizeClasses = {
    small: 'p-4',
    medium: 'p-6',
    large: 'p-8'
  }

  const hoverClasses = hover ? 'transform hover:scale-105' : ''

  const cardClasses = [
    baseClasses,
    variantClasses[variant],
    sizeClasses[size],
    hoverClasses,
    clickable ? 'cursor-pointer' : '',
    className
  ].filter(Boolean).join(' ')

  const handleClick = (e) => {
    if (clickable && onClick) {
      onClick(e)
    }
  }

  return (
    <div 
      className={cardClasses}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleClick}
    >
      {/* Background Effects */}
      {variant === 'gradient' && (
        <div className="absolute inset-0 bg-gradient-to-br from-blue-400/5 to-purple-400/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300 rounded-2xl"></div>
      )}
      
      {variant === 'glass' && (
        <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent opacity-50 rounded-2xl"></div>
      )}

      {/* Badge */}
      {badge && (
        <div className="absolute top-4 right-4 z-10">
          {badge}
        </div>
      )}

      {/* Header */}
      {header && (
        <div className="flex items-center justify-between mb-4 relative z-10">
          <div className="flex items-center space-x-3">
            {icon && (
              <div className="flex-shrink-0">
                {icon}
              </div>
            )}
            <div>
              {header.title && (
                <h3 className={`font-bold text-gray-900 ${
                  size === 'small' ? 'text-sm' : size === 'large' ? 'text-xl' : 'text-lg'
                }`}>
                  {header.title}
                </h3>
              )}
              {header.subtitle && (
                <p className="text-sm text-gray-500 mt-1">
                  {header.subtitle}
                </p>
              )}
            </div>
          </div>
          
          {actions && (
            <div className="flex items-center space-x-2">
              {actions}
            </div>
          )}
        </div>
      )}

      {/* Content */}
      <div className="relative z-10">
        {children}
      </div>

      {/* Footer */}
      {footer && (
        <div className="mt-4 pt-4 border-t border-gray-100 relative z-10">
          {footer}
        </div>
      )}

      {/* Hover Effects */}
      {clickable && isHovered && (
        <div className="absolute inset-0 bg-gradient-to-br from-blue-400/5 to-purple-400/5 rounded-2xl pointer-events-none"></div>
      )}
    </div>
  )
}

// Card Components for specific use cases
export const StatCard = ({ 
  title, 
  value, 
  change, 
  changeType, 
  icon, 
  trend = 'up',
  variant = 'default',
  onClick 
}) => {
  const TrendIcon = trend === 'up' ? TrendingUp : TrendingDown
  const trendColor = trend === 'up' ? 'text-green-500' : 'text-red-500'
  const bgColor = trend === 'up' ? 'bg-green-50' : 'bg-red-50'

  return (
    <Card 
      variant={variant} 
      clickable={!!onClick} 
      onClick={onClick}
      className="group"
    >
      <div className="flex items-center justify-between">
        <div className="flex-1">
          <p className="text-sm font-medium text-gray-500">{title}</p>
          <p className="text-2xl font-bold text-gray-900 mt-1">{value}</p>
          {change && (
            <div className={`flex items-center mt-2 text-sm ${trendColor}`}>
              <TrendIcon className="h-4 w-4 mr-1" />
              <span>{change}</span>
            </div>
          )}
        </div>
        
        {icon && (
          <div className={`p-3 rounded-xl ${bgColor} group-hover:scale-110 transition-transform duration-300`}>
            <div className={trendColor}>
              {icon}
            </div>
          </div>
        )}
      </div>
    </Card>
  )
}

export const ProductCard = ({ 
  product,
  onFavorite,
  onShare,
  onClick,
  variant = 'elevated'
}) => {
  const [isFavorited, setIsFavorited] = useState(product.isFavorite)

  const handleFavorite = (e) => {
    e.stopPropagation()
    setIsFavorited(!isFavorited)
    onFavorite?.(product.id)
  }

  const handleShare = (e) => {
    e.stopPropagation()
    onShare?.(product.id)
  }

  return (
    <Card 
      variant={variant} 
      clickable={!!onClick} 
      onClick={onClick}
      className="group overflow-hidden"
    >
      {/* Product Image */}
      {product.image && (
        <div className="relative h-48 -m-6 mb-4 rounded-t-2xl overflow-hidden">
          <img 
            src={product.image} 
            alt={product.name}
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
          
          {/* Action Buttons */}
          <div className="absolute top-4 right-4 flex space-x-2">
            <button
              onClick={handleFavorite}
              className="p-2 bg-white/90 backdrop-blur-sm rounded-lg hover:bg-white transition-colors"
            >
              <Heart className={`h-4 w-4 ${isFavorited ? 'fill-current text-red-500' : 'text-gray-600'}`} />
            </button>
            <button
              onClick={handleShare}
              className="p-2 bg-white/90 backdrop-blur-sm rounded-lg hover:bg-white transition-colors"
            >
              <Share2 className="h-4 w-4 text-gray-600" />
            </button>
          </div>
        </div>
      )}

      {/* Product Info */}
      <div>
        <div className="flex items-start justify-between mb-2">
          <h3 className="font-bold text-gray-900 group-hover:text-blue-600 transition-colors">
            {product.name}
          </h3>
          {product.rating && (
            <div className="flex items-center text-sm text-gray-500">
              <Star className="h-4 w-4 text-yellow-400 fill-current mr-1" />
              {product.rating}
            </div>
          )}
        </div>
        
        {product.description && (
          <p className="text-sm text-gray-600 mb-3 line-clamp-2">
            {product.description}
          </p>
        )}

        {product.tags && product.tags.length > 0 && (
          <div className="flex flex-wrap gap-1 mb-3">
            {product.tags.slice(0, 2).map((tag, index) => (
              <span
                key={index}
                className="px-2 py-1 text-xs bg-gradient-to-r from-blue-50 to-purple-50 text-blue-700 rounded-full"
              >
                {tag}
              </span>
            ))}
          </div>
        )}

        {product.price && (
          <div className="flex items-center justify-between">
            <span className="text-xl font-bold text-gray-900">
              ${product.price}
            </span>
            {product.originalPrice && (
              <span className="text-sm text-gray-500 line-through">
                ${product.originalPrice}
              </span>
            )}
          </div>
        )}
      </div>
    </Card>
  )
}

