import { useState, useEffect } from 'react'
import { Plus, Search, Edit2, Trash2, Package, AlertCircle, Archive, Save, X } from 'lucide-react'

const StockSubCategories = () => {
  const [subCategories, setSubCategories] = useState([])
  const [categories, setCategories] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedCategory, setSelectedCategory] = useState('')
  const [showAddForm, setShowAddForm] = useState(false)
  const [editingSubCategory, setEditingSubCategory] = useState(null)
  const [loading, setLoading] = useState(true)

  // Default subcategories data
  const defaultSubCategories = [
    // Paper subcategories
    { id: 1, categoryId: 1, categoryName: 'Paper', name: 'A4', description: 'Standard A4 paper size' },
    { id: 2, categoryId: 1, categoryName: 'Paper', name: 'A3', description: 'Standard A3 paper size' },
    { id: 3, categoryId: 1, categoryName: 'Paper', name: 'A5', description: 'Standard A5 paper size' },
    { id: 4, categoryId: 1, categoryName: 'Paper', name: 'Letter', description: 'US Letter paper size' },
    { id: 5, categoryId: 1, categoryName: 'Paper', name: 'Legal', description: 'US Legal paper size' },
    { id: 6, categoryId: 1, categoryName: 'Paper', name: 'Tabloid', description: 'Tabloid paper size' },
    { id: 7, categoryId: 1, categoryName: 'Paper', name: 'Photo Paper', description: 'Glossy photo paper' },
    { id: 8, categoryId: 1, categoryName: 'Paper', name: 'Cardstock', description: 'Heavy weight cardstock' },
    { id: 9, categoryId: 1, categoryName: 'Paper', name: 'Transparency', description: 'Transparent sheets' },
    { id: 10, categoryId: 1, categoryName: 'Paper', name: 'Label Paper', description: 'Adhesive label sheets' },
    { id: 11, categoryId: 1, categoryName: 'Paper', name: 'Newsprint', description: 'Newsprint paper' },
    { id: 12, categoryId: 1, categoryName: 'Paper', name: 'Art Paper', description: 'High quality art paper' },
    { id: 13, categoryId: 1, categoryName: 'Paper', name: 'Recycled Paper', description: 'Environmentally friendly paper' },
    
    // Ink subcategories
    { id: 14, categoryId: 2, categoryName: 'Ink', name: 'Black', description: 'Black ink' },
    { id: 15, categoryId: 2, categoryName: 'Ink', name: 'Color', description: 'Color ink' },
    { id: 16, categoryId: 2, categoryName: 'Ink', name: 'Cyan', description: 'Cyan ink' },
    { id: 17, categoryId: 2, categoryName: 'Ink', name: 'Magenta', description: 'Magenta ink' },
    { id: 18, categoryId: 2, categoryName: 'Ink', name: 'Yellow', description: 'Yellow ink' },
    { id: 19, categoryId: 2, categoryName: 'Ink', name: 'Photo Black', description: 'Photo black ink' },
    { id: 20, categoryId: 2, categoryName: 'Ink', name: 'Matte Black', description: 'Matte black ink' },
    { id: 21, categoryId: 2, categoryName: 'Ink', name: 'Gray Ink', description: 'Gray ink' },
    { id: 22, categoryId: 2, categoryName: 'Ink', name: 'White Ink', description: 'White ink' },
    { id: 23, categoryId: 2, categoryName: 'Ink', name: 'Metallic Ink', description: 'Metallic finish ink' },
    { id: 24, categoryId: 2, categoryName: 'Ink', name: 'UV Ink', description: 'UV curable ink' },
    { id: 25, categoryId: 2, categoryName: 'Ink', name: 'Solvent Ink', description: 'Solvent based ink' },
    { id: 26, categoryId: 2, categoryName: 'Ink', name: 'Eco-Solvent Ink', description: 'Eco-friendly solvent ink' },
  ]

  // Load data from localStorage on component mount
  useEffect(() => {
    // Load categories
    const savedCategories = localStorage.getItem('stockCategories')
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories))
      } catch (error) {
        console.error('Error parsing saved categories:', error)
      }
    }

    // Load subcategories
    const savedSubCategories = localStorage.getItem('stockSubCategories')
    if (savedSubCategories) {
      try {
        setSubCategories(JSON.parse(savedSubCategories))
      } catch (error) {
        console.error('Error parsing saved subcategories:', error)
        setSubCategories(defaultSubCategories)
        localStorage.setItem('stockSubCategories', JSON.stringify(defaultSubCategories))
      }
    } else {
      setSubCategories(defaultSubCategories)
      localStorage.setItem('stockSubCategories', JSON.stringify(defaultSubCategories))
    }
    setLoading(false)
  }, [])

  // Save subcategories to localStorage whenever they change
  useEffect(() => {
    if (subCategories.length > 0) {
      localStorage.setItem('stockSubCategories', JSON.stringify(subCategories))
    }
  }, [subCategories])

  const filteredSubCategories = subCategories.filter(subCategory =>
    subCategory.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    subCategory.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (selectedCategory && subCategory.categoryId === parseInt(selectedCategory))
  )

  const handleDelete = (id) => {
    if (window.confirm('Are you sure you want to delete this subcategory?')) {
      const updatedSubCategories = subCategories.filter(sc => sc.id !== id)
      setSubCategories(updatedSubCategories)
    }
  }

  const handleEdit = (subCategory) => {
    setEditingSubCategory(subCategory)
    setShowAddForm(true)
  }

  const handleSave = (e) => {
    e.preventDefault()
    const formData = new FormData(e.target)
    const selectedCategoryData = categories.find(cat => cat.id === parseInt(formData.get('categoryId')))
    
    const newSubCategory = {
      id: editingSubCategory ? editingSubCategory.id : Date.now(),
      categoryId: parseInt(formData.get('categoryId')),
      categoryName: selectedCategoryData?.name || '',
      name: formData.get('name'),
      description: formData.get('description')
    }

    let updatedSubCategories
    if (editingSubCategory) {
      updatedSubCategories = subCategories.map(sc => sc.id === editingSubCategory.id ? newSubCategory : sc)
    } else {
      updatedSubCategories = [...subCategories, newSubCategory]
    }

    setSubCategories(updatedSubCategories)
    setShowAddForm(false)
    setEditingSubCategory(null)
  }

  const handleClose = () => {
    setShowAddForm(false)
    setEditingSubCategory(null)
  }

  const handleAdd = () => {
    setEditingSubCategory(null)
    setShowAddForm(true)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Stock Subcategories Management</h2>
        <button
          onClick={handleAdd}
          className="flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition-colors text-base font-medium"
        >
          <Plus size={20} />
          Add Subcategory
        </button>
      </div>

      {/* Filters */}
      <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
          <input
            type="text"
            placeholder="Search subcategories..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 w-full"
          />
        </div>
        <div>
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">All Categories</option>
            {categories.map(category => (
              <option key={category.id} value={category.id}>
                {category.name}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Subcategories List */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Subcategory Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Description</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredSubCategories.length === 0 ? (
                <tr>
                  <td colSpan="4" className="px-6 py-4 text-center text-gray-500">
                    No subcategories found
                  </td>
                </tr>
              ) : (
                filteredSubCategories.map((subCategory) => (
                  <tr key={subCategory.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <Archive className="text-green-500 mr-3" size={20} />
                        <div className="text-sm font-medium text-gray-900">{subCategory.name}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-blue-100 text-blue-800">
                        {subCategory.categoryName}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {subCategory.description}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <button
                        onClick={() => handleEdit(subCategory)}
                        className="text-blue-600 hover:text-blue-900 mr-3 p-2 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Edit Subcategory"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button
                        onClick={() => handleDelete(subCategory.id)}
                        className="text-red-600 hover:text-red-900 p-2 hover:bg-red-50 rounded-lg transition-colors"
                        title="Delete Subcategory"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Subcategory Modal */}
      {showAddForm && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-96 shadow-lg rounded-md bg-white">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-medium text-gray-900">
                {editingSubCategory ? 'Edit Subcategory' : 'Add New Subcategory'}
              </h3>
              <button
                onClick={handleClose}
                className="text-gray-400 hover:text-gray-500"
              >
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSave} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                <select
                  name="categoryId"
                  defaultValue={editingSubCategory?.categoryId || ''}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value="">Select Category</option>
                  {categories.map(category => (
                    <option key={category.id} value={category.id}>
                      {category.name}
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Subcategory Name</label>
                <input
                  type="text"
                  name="name"
                  defaultValue={editingSubCategory?.name || ''}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea
                  name="description"
                  rows="3"
                  defaultValue={editingSubCategory?.description || ''}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={handleClose}
                  className="px-6 py-3 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 text-base font-medium transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-3 bg-blue-600 text-white rounded-md hover:bg-blue-700 flex items-center gap-2 text-base font-medium transition-colors"
                >
                  <Save size={18} />
                  {editingSubCategory ? 'Update' : 'Save'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default StockSubCategories
