import { useState, useEffect } from 'react'
import { customersAPI } from '../../services/api'
import { toast } from 'react-hot-toast'
import { Search, Edit2, Trash2, User, Phone, Mail, MapPin, Camera, X, Filter, Download, Eye } from 'lucide-react'

const CustomerList = () => {
  const [customers, setCustomers] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedCustomer, setSelectedCustomer] = useState(null)
  const [showDetails, setShowDetails] = useState(false)
  const [filters, setFilters] = useState({
    refer: '',
    sortBy: 'createdAt',
    sortOrder: 'desc'
  })

  useEffect(() => {
    fetchCustomers()
  }, [])

  const fetchCustomers = async () => {
    try {
      setLoading(true)
      const response = await customersAPI.getAll()
      setCustomers(response.data)
    } catch (error) {
      toast.error('Failed to fetch customers')
      console.error('Error fetching customers:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleDelete = async (customerId) => {
    if (window.confirm('Are you sure you want to delete this customer?')) {
      try {
        await customersAPI.delete(customerId)
        toast.success('Customer deleted successfully')
        fetchCustomers()
      } catch (error) {
        toast.error('Failed to delete customer')
        console.error('Error deleting customer:', error)
      }
    }
  }

  const handleEdit = (customer) => {
    // Navigate to add customer tab with edit mode
    window.history.pushState({}, '', `/customer-management?tab=add-customer&edit=${customer._id}`)
    window.dispatchEvent(new PopStateEvent('popstate'))
  }

  const handleViewDetails = (customer) => {
    setSelectedCustomer(customer)
    setShowDetails(true)
  }

  const getImageUrl = (photoPath) => {
    if (!photoPath) return null
    if (photoPath.startsWith('http')) {
      return photoPath
    }
    if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
      return `http://localhost:5001/uploads/${photoPath}`
    } else {
      return `https://two026backend.onrender.com/uploads/${photoPath}`
    }
  }

  const handleImageError = (e) => {
    e.target.style.display = 'none'
    e.target.nextSibling.style.display = 'flex'
  }

  const filteredCustomers = customers.filter(customer => {
    const matchesSearch = 
      customer.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      customer.customerId.toLowerCase().includes(searchTerm.toLowerCase()) ||
      customer.emailId?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      customer.cellNo.includes(searchTerm)
    
    const matchesRefer = !filters.refer || customer.refer === filters.refer
    
    return matchesSearch && matchesRefer
  }).sort((a, b) => {
    const aValue = a[filters.sortBy]
    const bValue = b[filters.sortBy]
    const modifier = filters.sortOrder === 'asc' ? 1 : -1
    
    if (aValue < bValue) return -1 * modifier
    if (aValue > bValue) return 1 * modifier
    return 0
  })

  const exportToCSV = () => {
    const headers = ['Customer ID', 'Name', 'Father Name', 'Date of Birth', 'Address', 'Pincode', 'Phone', 'Email', 'Refer By']
    const csvContent = [
      headers.join(','),
      ...filteredCustomers.map(customer => [
        customer.customerId,
        customer.name,
        customer.fatherName,
        customer.dateOfBirth,
        `"${customer.address}"`,
        customer.pincode,
        customer.cellNo,
        customer.emailId || '',
        customer.refer || ''
      ].join(','))
    ].join('\n')

    const blob = new Blob([csvContent], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `customers_${new Date().toISOString().split('T')[0]}.csv`
    a.click()
    window.URL.revokeObjectURL(url)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6 w-full max-w-7xl mx-auto">
      {/* Search and Filters */}
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
        <div className="lg:col-span-2">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-5 w-5" />
            <input
              type="text"
              placeholder="Search customers by name, ID, email, or phone..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        </div>
        
        <div>
          <select
            value={filters.refer}
            onChange={(e) => setFilters({...filters, refer: e.target.value})}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            <option value="">All Referrals</option>
            <option value="Self">Self</option>
            <option value="VAO's">VAO's</option>
            <option value="Others">Others</option>
            <option value="Exist Customer">Exist Customer</option>
          </select>
        </div>
        
        <div className="flex gap-2">
          <select
            value={`${filters.sortBy}-${filters.sortOrder}`}
            onChange={(e) => {
              const [sortBy, sortOrder] = e.target.value.split('-')
              setFilters({...filters, sortBy, sortOrder})
            }}
            className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            <option value="createdAt-desc">Newest First</option>
            <option value="createdAt-asc">Oldest First</option>
            <option value="name-asc">Name (A-Z)</option>
            <option value="name-desc">Name (Z-A)</option>
          </select>
          
          <button
            onClick={exportToCSV}
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
            title="Export to CSV"
          >
            <Download className="h-5 w-5" />
          </button>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-blue-50 p-4 rounded-lg border border-blue-200">
          <div className="text-blue-600 text-sm font-medium">Total Customers</div>
          <div className="text-2xl font-bold text-blue-900">{customers.length}</div>
        </div>
        <div className="bg-green-50 p-4 rounded-lg border border-green-200">
          <div className="text-green-600 text-sm font-medium">Filtered Results</div>
          <div className="text-2xl font-bold text-green-900">{filteredCustomers.length}</div>
        </div>
        <div className="bg-purple-50 p-4 rounded-lg border border-purple-200">
          <div className="text-purple-600 text-sm font-medium">New This Month</div>
          <div className="text-2xl font-bold text-purple-900">
            {customers.filter(c => new Date(c.createdAt) > new Date(new Date().setMonth(new Date().getMonth() - 1))).length}
          </div>
        </div>
        <div className="bg-amber-50 p-4 rounded-lg border border-amber-200">
          <div className="text-amber-600 text-sm font-medium">With Photos</div>
          <div className="text-2xl font-bold text-amber-900">
            {customers.filter(c => c.photo).length}
          </div>
        </div>
      </div>

      {/* Customers Table */}
      <div className="bg-blue-50 rounded-lg shadow-sm border border-blue-200 overflow-hidden">
        {filteredCustomers.length === 0 ? (
          <div className="p-8 text-center text-gray-500">
            {searchTerm || filters.refer ? 'No customers found matching your criteria.' : 'No customers found. Add your first customer to get started.'}
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Photo
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Customer ID
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Name
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Contact
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Address
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {filteredCustomers.map((customer) => (
                  <tr key={customer._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="relative">
                        {customer.photo ? (
                          <>
                            <img 
                              src={getImageUrl(customer.photo)}
                              alt={customer.name}
                              className="h-10 w-10 rounded-full object-cover border-2 border-gray-200"
                              onError={handleImageError}
                            />
                            <div 
                              className="h-10 w-10 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300 absolute top-0 left-0"
                              style={{ display: 'none' }}
                            >
                              <User className="h-5 w-5 text-gray-400" />
                            </div>
                          </>
                        ) : (
                          <div className="h-10 w-10 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300">
                            <User className="h-5 w-5 text-gray-400" />
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {customer.customerId}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <User className="h-4 w-4 text-gray-400 mr-2" />
                        <div>
                          <div className="text-sm font-medium text-gray-900">{customer.name}</div>
                          <div className="text-xs text-gray-500">
                            {new Date(customer.dateOfBirth).toLocaleDateString()}
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="space-y-1">
                        <div className="flex items-center text-sm text-gray-900">
                          <Phone className="h-3 w-3 text-gray-400 mr-1" />
                          {customer.cellNo}
                        </div>
                        <div className="flex items-center text-sm text-gray-900">
                          <Mail className="h-3 w-3 text-gray-400 mr-1" />
                          {customer.emailId || 'N/A'}
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-900">
                        <div className="flex items-start">
                          <MapPin className="h-3 w-3 text-gray-400 mr-1 mt-0.5" />
                          <div>
                            <div>{customer.address}</div>
                            <div className="text-xs text-gray-500">{customer.pincode}</div>
                          </div>
                        </div>
                      </div>
                      {customer.refer && (
                        <div className="text-xs text-gray-500 mt-1">
                          Referred by: {customer.refer}
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex items-center space-x-2">
                        <button
                          onClick={() => handleViewDetails(customer)}
                          className="text-blue-600 hover:text-blue-900 p-1 rounded hover:bg-blue-50 transition-colors"
                          title="View details"
                        >
                          <Eye className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleEdit(customer)}
                          className="text-amber-600 hover:text-amber-900 p-1 rounded hover:bg-amber-50 transition-colors"
                          title="Edit customer"
                        >
                          <Edit2 className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleDelete(customer._id)}
                          className="text-red-600 hover:text-red-900 p-1 rounded hover:bg-red-50 transition-colors"
                          title="Delete customer"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Customer Details Modal */}
      {showDetails && selectedCustomer && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-start mb-4">
              <h2 className="text-xl font-bold">Customer Details</h2>
              <button
                onClick={() => setShowDetails(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <X className="h-6 w-6" />
              </button>
            </div>
            
            <div className="space-y-4">
              <div className="flex items-center space-x-4">
                {selectedCustomer.photo ? (
                  <img 
                    src={getImageUrl(selectedCustomer.photo)}
                    alt={selectedCustomer.name}
                    className="h-20 w-20 rounded-full object-cover border-2 border-gray-200"
                    onError={handleImageError}
                  />
                ) : (
                  <div className="h-20 w-20 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300">
                    <User className="h-10 w-10 text-gray-400" />
                  </div>
                )}
                <div>
                  <h3 className="text-lg font-semibold">{selectedCustomer.name}</h3>
                  <p className="text-gray-600">{selectedCustomer.customerId}</p>
                </div>
              </div>
              
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-sm font-medium text-gray-500">Father Name</label>
                  <p className="text-gray-900">{selectedCustomer.fatherName}</p>
                </div>
                <div>
                  <label className="text-sm font-medium text-gray-500">Date of Birth</label>
                  <p className="text-gray-900">{new Date(selectedCustomer.dateOfBirth).toLocaleDateString()}</p>
                </div>
                <div>
                  <label className="text-sm font-medium text-gray-500">Phone</label>
                  <p className="text-gray-900">{selectedCustomer.cellNo}</p>
                </div>
                <div>
                  <label className="text-sm font-medium text-gray-500">Email</label>
                  <p className="text-gray-900">{selectedCustomer.emailId || 'N/A'}</p>
                </div>
                <div className="col-span-2">
                  <label className="text-sm font-medium text-gray-500">Address</label>
                  <p className="text-gray-900">{selectedCustomer.address}, {selectedCustomer.pincode}</p>
                </div>
                {selectedCustomer.refer && (
                  <div className="col-span-2">
                    <label className="text-sm font-medium text-gray-500">Referred By</label>
                    <p className="text-gray-900">{selectedCustomer.refer}</p>
                  </div>
                )}
              </div>
              
              <div className="flex justify-end space-x-3 pt-4">
                <button
                  onClick={() => {
                    setShowDetails(false)
                    handleEdit(selectedCustomer)
                  }}
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                >
                  Edit Customer
                </button>
                <button
                  onClick={() => setShowDetails(false)}
                  className="px-4 py-2 bg-gray-200 text-gray-800 rounded-lg hover:bg-gray-300 transition-colors"
                >
                  Close
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default CustomerList
